import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MessageSquare, Send, X, Loader2, Sparkles, ChevronDown, Cpu } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { generateResponse } from "@/lib/openai";
import pdfContent from '@/assets/sample.pdf?raw';

interface Message {
  role: 'user' | 'assistant';
  content: string;
}

const Chatbot = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([
    "What are your web development prices?",
    "Tell me about Opus Africa",
    "Tell me about your team structure",
    "What's included in maintenance plans?"
  ]);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLTextAreaElement>(null);

  const welcomeMessage = "👋 Hi there! I'm Opus Africa AI assistant. I can help you with information about our software development services and pricing. Feel free to ask any questions!";

  useEffect(() => {
    if (isOpen && messages.length === 0) {
      setMessages([{ role: 'assistant', content: welcomeMessage }]);
    }
  }, [isOpen]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSuggestionClick = async (text: string) => {
    setInput(text);
    const fakeEvent = new Event('submit') as any;
    await handleSubmit(fakeEvent);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage = input.trim();
    setInput('');

    // Add user message immediately
    const newUserMessage = { role: 'user' as const, content: userMessage };
    setMessages(prev => [...prev, newUserMessage]);
    setIsLoading(true);

    try {
      // Get all messages except the welcome message for context
      const contextMessages = messages.filter((_msg, index) => index !== 0);
      const response = await generateResponse([...contextMessages, newUserMessage], pdfContent);

      setMessages(prev => [...prev, {
        role: 'assistant',
        content: response.answer || "I apologize, but I couldn't generate a response. Please try again."
      }]);

      // Update suggestions with the new ones from the AI
      setSuggestions(response.suggestions);
    } catch (error) {
      console.error('Error:', error);
      setMessages(prev => [...prev, {
        role: 'assistant',
        content: "I apologize, but I encountered an error. Please try again."
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit(e);
    }
  };

  const toggleChat = () => setIsOpen(!isOpen);

  return (
    <>
      {/* Chat Button */}
      <motion.button
        initial={{ scale: 0 }}
        animate={{ scale: 1 }}
        whileHover={{ scale: 1.1 }}
        whileTap={{ scale: 0.9 }}
        onClick={toggleChat}
        className="fixed bottom-6 right-6 z-50 bg-green-500 hover:bg-green-600 text-white p-4 rounded-full shadow-lg transition-all duration-300 hover:scale-110"
      >
        <MessageSquare className="h-6 w-6" />
      </motion.button>

      {/* Chat Window */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 20, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 20, scale: 0.95 }}
            transition={{ duration: 0.2 }}
            className="fixed bottom-24 right-6 w-80 h-[475px] bg-white dark:bg-gray-800 rounded-xl shadow-2xl flex flex-col overflow-hidden border border-gray-200 dark:border-gray-700"
          >
            {/* Header */}
            <div className="p-3 bg-gradient-to-r from-blue-600 to-blue-700 text-white flex items-center justify-between">
              <div className="flex items-center space-x-2">
                <div className="bg-white/20 p-2 rounded-lg">
                  <Cpu className="h-5 w-5" />
                </div>
                <div>
                  <h3 className="font-semibold">Opus Africa AI Assistant</h3>
                  <p className="text-xs text-blue-100">Your 24/7 Online Friend.</p>
                </div>
              </div>
              <button
                onClick={toggleChat}
                className="hover:bg-white/20 p-2 rounded-lg transition-colors duration-200"
              >
                <X className="h-5 w-5" />
              </button>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50 dark:bg-gray-900">
              {messages.map((message, index) => (
                <motion.div
                  key={index}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.2 }}
                  className={`flex ${message.role === 'user' ? 'justify-end' : 'justify-start'}`}
                >
                  {message.role === 'assistant' && (
                    <div className="w-7 h-7 rounded-full bg-blue-600 flex items-center justify-center mr-2">
                      <Sparkles className="h-4 w-4 text-white" />
                    </div>
                  )}
                  <div
                    className={`max-w-[80%] p-3 rounded-2xl ${
                      message.role === 'user'
                        ? 'bg-blue-600 text-white rounded-br-none'
                        : 'bg-white dark:bg-gray-800 text-gray-900 dark:text-white shadow-md rounded-bl-none'
                    }`}
                  >
                    <ReactMarkdown className="prose dark:prose-invert max-w-none text-sm">
                      {message.content}
                    </ReactMarkdown>
                  </div>
                </motion.div>
              ))}
              {isLoading && (
                <motion.div
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="flex items-center space-x-2"
                >
                  <div className="w-7 h-7 rounded-full bg-blue-600 flex items-center justify-center">
                    <Loader2 className="h-4 w-4 text-white animate-spin" />
                  </div>
                  <div className="bg-white dark:bg-gray-800 p-3 rounded-2xl shadow-md">
                    <div className="flex space-x-2">
                      <div className="w-2 h-2 bg-blue-600 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                      <div className="w-2 h-2 bg-blue-600 rounded-full animate-bounce" style={{ animationDelay: '200ms' }} />
                      <div className="w-2 h-2 bg-blue-600 rounded-full animate-bounce" style={{ animationDelay: '400ms' }} />
                    </div>
                  </div>
                </motion.div>
              )}
              <div ref={messagesEndRef} />
            </div>

            {/* Suggestions */}
            <div className="p-3 bg-white dark:bg-gray-800 border-t dark:border-gray-700">
              <p className="text-xs text-gray-500 dark:text-gray-400 mb-2">
                {messages.length === 1 ? "Suggested questions:" : "Take a look on the suggested questions to explore more :"}
              </p>
              <div className="flex flex-wrap gap-2 max-h-24 overflow-y-auto relative">
                {suggestions.map((suggestion, index) => (
                  <button
                    key={index}
                    onClick={() => handleSuggestionClick(suggestion)}
                    className="text-xs bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 px-3 py-1 rounded-full hover:bg-gray-200 dark:hover:bg-gray-600 transition-colors duration-200"
                  >
                    {suggestion}
                  </button>
                ))}
                <motion.div
                  className="absolute bottom-1 inset-x-0 flex justify-center"
                  animate={{ y: [0, 5, 0] }}
                  transition={{ duration: 1.5, repeat: Infinity }}
                >
                  <ChevronDown className="h-4 w-4 text-gray-500 dark:text-gray-400" />
                </motion.div>
              </div>
            </div>

            {/* Input */}
            <form onSubmit={handleSubmit} className="p-3 bg-white dark:bg-gray-800 border-t dark:border-gray-700">
              <div className="flex space-x-2">
                <textarea
                  ref={inputRef}
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={handleKeyDown}
                  placeholder="Ask About Opus Africa..."
                  className="flex-1 p-2 border border-gray-200 dark:border-gray-600 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 dark:bg-gray-700 dark:text-white resize-none placeholder-gray-400 dark:placeholder-gray-500 text-sm"
                  rows={1}
                />
                <button
                  type="submit"
                  disabled={isLoading || !input.trim()}
                  className="bg-gradient-to-r from-blue-600 to-blue-700 text-white p-2 rounded-xl hover:from-blue-700 hover:to-blue-800 transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:from-blue-600 disabled:hover:to-blue-700"
                >
                  <Send className="h-5 w-5" />
                </button>
              </div>
            </form>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

export default Chatbot;

import { useState, useEffect } from 'react';
import { Outlet, useNavigate } from 'react-router-dom';
import axios from 'axios';
import Navbar from '@/components/navbar';
import Sidebar from '@/components/layout/Sidebar';
import Footer from '@/components/layout/Footer';
import { Menu, X } from 'lucide-react';
import DashboardLoader from '@/lib/loader';

interface UserProfile {
  id: string;
  name: string;
  email: string;
  username: string;
  role: string;
  profile_image: string | null;
  bio: string | null;
  roles?: string[];
  permissions?: string[];
}

const SIDEBAR_WIDTH = 256; // 256px when expanded
const SIDEBAR_COLLAPSED_WIDTH = 80; // 80px when collapsed
const NAVBAR_HEIGHT = 72; // 72px for Navbar (Condensed)
const HEADER_HEIGHT = 72; // additional mobile header height

interface VendorProfile {
  logo_url?: string | null;
  business_name?: string;
  dashboard_settings?: { show_logo_in_sidebar?: boolean; tagline?: string };
}

const DashboardLayout = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [vendorProfile, setVendorProfile] = useState<VendorProfile | null>(null);
  const [loading, setLoading] = useState(true);
  const [sidebarOpen, setSidebarOpen] = useState(window.innerWidth >= 768);
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  const navigate = useNavigate();

  const handleLogout = async () => {
    try {
      const token = localStorage.getItem('token');
      if (token) {
        await axios.post(`${import.meta.env.VITE_API_URL}/admin/logout`, null, {
          headers: { Authorization: `Bearer ${token}` },
        });
      }
    } catch (_) {
      // ignore
    } finally {
      localStorage.removeItem('token');
      setUser(null);
      navigate('/login');
    }
  };

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (!token) {
      navigate('/login');
      return;
    }
    axios.get(`${import.meta.env.VITE_API_URL}/admin/account`, {
      headers: { Authorization: `Bearer ${token}` },
    })
      .then((res) => {
        const userData = res.data;
        // Ensure roles/permissions are arrays for backward compatibility
        userData.roles = userData.roles || (userData.role ? [userData.role] : []);
        userData.permissions = userData.permissions || [];
        setUser(userData);
        setLoading(false);
      })
      .catch((err) => {
        console.error('Failed to fetch user:', err);
        localStorage.removeItem('token');
        navigate('/login');
      });
  }, [navigate]);

  useEffect(() => {
    if (!user || user.role !== 'vendor') {
      setVendorProfile(null);
      return;
    }
    const token = localStorage.getItem('token');
    if (!token) return;
    axios.get(`${import.meta.env.VITE_API_URL}/vendor/profile`, {
      headers: { Authorization: `Bearer ${token}` },
    })
      .then((res) => {
        if (res.data?.status === 200 && res.data?.vendor) {
          setVendorProfile({
            logo_url: res.data.vendor.logo_url,
            business_name: res.data.vendor.business_name,
            dashboard_settings: res.data.vendor.dashboard_settings,
          });
        }
      })
      .catch(() => setVendorProfile(null));
  }, [user?.id, user?.role]);

  useEffect(() => {
    const handleResize = () => {
      const mobile = window.innerWidth < 768;
      setIsMobile(mobile);
      setSidebarOpen(!mobile);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  if (loading || !user) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-gray-50 dark:bg-gray-900">
        <DashboardLoader
          title="Authenticating..."
          subtitle="Please wait while we verify your credentials"
        />
      </div>
    );
  }

  const topPadding = isMobile ? HEADER_HEIGHT : 0;

  return (
    <>
      {/* Navbar stays fixed at top */}
      <Navbar
        user={user}
        vendorProfile={vendorProfile}
        onToggleSidebar={() => setSidebarOpen((prev) => !prev)}
        showSidebarToggle={!isMobile}
        sidebarOpen={sidebarOpen}
        onLogout={handleLogout}
      />

      <div className="flex flex-col min-h-screen bg-gray-50 dark:bg-gray-900">

        {/* Fixed Sidebar with top offset */}
        <div
          className={`fixed left-0 z-20 transition-all duration-300 ease-in-out
            ${isMobile ? (sidebarOpen ? 'translate-x-0' : '-translate-x-full') : 'translate-x-0'}`}
          style={{
            width: isMobile ? `${SIDEBAR_WIDTH}px` : (sidebarOpen ? `${SIDEBAR_WIDTH}px` : `${SIDEBAR_COLLAPSED_WIDTH}px`),
            top: `${NAVBAR_HEIGHT}px`,
            height: `calc(100% - ${NAVBAR_HEIGHT}px)`
          }}
        >
          <Sidebar
            user={user}
            vendorProfile={vendorProfile}
            sidebarOpen={sidebarOpen}
            isMobile={isMobile}
            onLogout={handleLogout}
            onCloseMobile={() => setSidebarOpen(false)}
          />
        </div>

        {/* Overlay for mobile */}
        {isMobile && sidebarOpen && (
          <div onClick={() => setSidebarOpen(false)} className="fixed inset-0 bg-black/40 z-10"></div>
        )}

        {/* Mobile Greeting Header */}
        {isMobile && (
          <header
            className="fixed left-0 right-0 z-10 flex items-center justify-between p-4 bg-white/95 dark:bg-slate-800/95 backdrop-blur-md border-b border-slate-200/50 dark:border-slate-700/50 transition-all duration-300 ease-in-out"
            style={{
              top: `${NAVBAR_HEIGHT}px`,
              marginLeft: 0,
              height: `${HEADER_HEIGHT}px`,
            }}
          >
            <button
              onClick={() => setSidebarOpen(!sidebarOpen)}
              className="p-2 rounded-md text-gray-500 hover:text-blue-600 hover:bg-gray-100 dark:text-gray-400 dark:hover:text-blue-400 dark:hover:bg-gray-700"
            >
              {sidebarOpen ? <X /> : <Menu />}
            </button>

            <div className="w-10"></div>
          </header>
        )}

        {/* Content area below fixed header */}
        <div
          className="flex flex-col flex-1 min-h-screen transition-all duration-300 ease-in-out"
          style={{
            marginLeft: isMobile ? 0 : (sidebarOpen ? `${SIDEBAR_WIDTH}px` : `${SIDEBAR_COLLAPSED_WIDTH}px`),
            paddingTop: `${topPadding}px`
          }}
        >
          <main className="flex-1 overflow-y-auto">
            <Outlet context={{ user, setUser, vendorProfile, setVendorProfile }} />
          </main>

          <Footer />
        </div>
      </div>
    </>
  );
};

export default DashboardLayout;

import { createContext, useContext, useEffect, useState } from "react";

type Theme = "dark" | "light";

type ThemeProviderProps = {
  children: React.ReactNode;
  defaultTheme?: Theme;
  storageKey?: string;
};

type ThemeProviderState = {
  theme: Theme;
  setTheme: (theme: Theme) => void;
};

const initialState: ThemeProviderState = {
  theme: "light",
  setTheme: () => null,
};

const ThemeProviderContext = createContext<ThemeProviderState>(initialState);

export function ThemeProvider({
  children,
  defaultTheme = "light",
  storageKey = "opus-ui-theme",
  ...props
}: ThemeProviderProps) {
  const [theme, setTheme] = useState<Theme>(
    () => (localStorage.getItem(storageKey) as Theme) || defaultTheme
  );

  useEffect(() => {
    const root = window.document.documentElement;
    root.classList.remove("light", "dark");
    root.classList.add(theme);
  }, [theme]);

  const value = {
    theme,
    setTheme: (theme: Theme) => {
      localStorage.setItem(storageKey, theme);
      setTheme(theme);
    },
  };

  return (
    <ThemeProviderContext.Provider {...props} value={value}>
      {children}
    </ThemeProviderContext.Provider>
  );
}

export const useTheme = () => {
  const context = useContext(ThemeProviderContext);

  if (context === undefined)
    throw new Error("useTheme must be used within a ThemeProvider");

  return context;
};

import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive:
          "bg-destructive text-destructive-foreground hover:bg-destructive/90",
        outline:
          "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-10 px-4 py-2",
        sm: "h-9 rounded-md px-3",
        lg: "h-11 rounded-md px-8",
        icon: "h-10 w-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button";
    return (
      <Comp
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        {...props}
      />
    );
  }
);
Button.displayName = "Button";

export { Button, buttonVariants };

import { useState, useEffect } from 'react';

export const useAuth = () => {
    const [user, setUser] = useState<any>(null);

    useEffect(() => {
        const storedUser = localStorage.getItem('user');
        if (storedUser) {
            setUser(JSON.parse(storedUser));
        }
    }, []);

    const login = (userData: any, token: string) => {
        localStorage.setItem('token', token);
        localStorage.setItem('user', JSON.stringify(userData));
        setUser(userData);
    };

    const logout = () => {
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        setUser(null);
    };

    return { user, login, logout };
};

import { useState, useEffect } from 'react';
import axios from 'axios';
import Swal from 'sweetalert2';
import { User, Mail, AtSign, Lock, Save, Loader2 } from 'lucide-react';
import DashboardLoader from '@/lib/loader';

interface UserProfile {
    id: string;
    name: string;
    email: string;
    username: string;
    role: string;
    bio: string;
    profile_image: string | null;
    roles?: string[];
    permissions?: string[];
}

const Account = () => {
    const [profile, setProfile] = useState<UserProfile | null>(null);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);

    // Password change state
    const [currentPassword, setCurrentPassword] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [passwordSaving, setPasswordSaving] = useState(false);

    useEffect(() => {
        fetchProfile();
    }, []);

    const fetchProfile = async () => {
        try {
            const token = localStorage.getItem('token');
            const response = await axios.get(`${import.meta.env.VITE_API_URL}/admin/account`, {
                headers: { Authorization: `Bearer ${token}` }
            });
            setProfile(response.data);
        } catch (error) {
            console.error('Failed to fetch profile', error);
            Swal.fire({
                icon: 'error',
                title: 'Error',
                text: 'Failed to load profile details',
                toast: true,
                position: 'top-end',
                showConfirmButton: false,
                timer: 3000
            });
        } finally {
            setLoading(false);
        }
    };

    const handleProfileUpdate = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!profile) return;

        setSaving(true);
        try {
            const token = localStorage.getItem('token');
            await axios.put(`${import.meta.env.VITE_API_URL}/admin/account`, profile, {
                headers: { Authorization: `Bearer ${token}` }
            });
            Swal.fire({
                icon: 'success',
                title: 'Success',
                text: 'Profile updated successfully',
                toast: true,
                position: 'top-end',
                showConfirmButton: false,
                timer: 3000
            });
        } catch (error: any) {
            console.error('Update failed', error);
            Swal.fire({
                icon: 'error',
                title: 'Error',
                text: error.response?.data?.message || 'Failed to update profile',
                toast: true,
                position: 'top-end',
                showConfirmButton: false,
                timer: 3000
            });
        } finally {
            setSaving(false);
        }
    };

    const handlePasswordChange = async (e: React.FormEvent) => {
        e.preventDefault();
        if (newPassword !== confirmPassword) {
            Swal.fire({
                icon: 'error',
                title: 'Error',
                text: 'New passwords do not match',
                toast: true,
                position: 'top-end',
                showConfirmButton: false,
                timer: 3000
            });
            return;
        }

        setPasswordSaving(true);
        try {
            const token = localStorage.getItem('token');
            await axios.put(`${import.meta.env.VITE_API_URL}/admin/account/password`, {
                current_password: currentPassword,
                new_password: newPassword,
                new_password_confirmation: confirmPassword
            }, {
                headers: { Authorization: `Bearer ${token}` }
            });

            Swal.fire({
                icon: 'success',
                title: 'Success',
                text: 'Password changed successfully',
                toast: true,
                position: 'top-end',
                showConfirmButton: false,
                timer: 3000
            });
            setCurrentPassword('');
            setNewPassword('');
            setConfirmPassword('');
        } catch (error: any) {
            console.error('Password change failed', error);
            Swal.fire({
                icon: 'error',
                title: 'Error',
                text: error.response?.data?.message || 'Failed to change password',
                toast: true,
                position: 'top-end',
                showConfirmButton: false,
                timer: 3000
            });
        } finally {
            setPasswordSaving(false);
        }
    };

    if (loading) {
        return <DashboardLoader title="Loading Profile..." subtitle="Please wait" />;
    }

    if (!profile) return null;

    return (
        <div className="max-w-4xl mx-auto p-6 space-y-8">
            <div>
                <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Account Settings</h1>
                <p className="text-gray-500 dark:text-gray-400 mt-1">Manage your profile and security settings</p>
            </div>

            <div className="grid grid-cols-1 gap-8 md:grid-cols-2">
                {/* Profile Details Section */}
                <div className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 p-6">
                    <h2 className="text-lg font-semibold text-gray-900 dark:text-white mb-6 flex items-center gap-2">
                        <User className="w-5 h-5 text-blue-500" />
                        Profile Information
                    </h2>

                    <form onSubmit={handleProfileUpdate} className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Full Name</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                    <User className="h-5 w-5 text-gray-400" />
                                </div>
                                <input
                                    type="text"
                                    value={profile.name}
                                    onChange={(e) => setProfile({ ...profile, name: e.target.value })}
                                    className="pl-10 w-full rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-900 dark:text-white px-4 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-colors"
                                    required
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Email Address</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                    <Mail className="h-5 w-5 text-gray-400" />
                                </div>
                                <input
                                    type="email"
                                    value={profile.email}
                                    onChange={(e) => setProfile({ ...profile, email: e.target.value })}
                                    className="pl-10 w-full rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-900 dark:text-white px-4 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-colors"
                                    required
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Username</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                    <AtSign className="h-5 w-5 text-gray-400" />
                                </div>
                                <input
                                    type="text"
                                    value={profile.username}
                                    onChange={(e) => setProfile({ ...profile, username: e.target.value })}
                                    className="pl-10 w-full rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-900 dark:text-white px-4 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-colors"
                                    required
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Bio</label>
                            <textarea
                                value={profile.bio || ''}
                                onChange={(e) => setProfile({ ...profile, bio: e.target.value })}
                                rows={3}
                                className="w-full rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-900 dark:text-white px-4 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-colors resize-none"
                                placeholder="Tell us a little about yourself..."
                            />
                        </div>

                        <div className="pt-4">
                            <button
                                type="submit"
                                disabled={saving}
                                className="w-full flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white font-medium py-2.5 px-4 rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                {saving ? (
                                    <>
                                        <Loader2 className="w-5 h-5 animate-spin" />
                                        Saving...
                                    </>
                                ) : (
                                    <>
                                        <Save className="w-5 h-5" />
                                        Save Changes
                                    </>
                                )}
                            </button>
                        </div>
                    </form>
                </div>

                {/* Security Section */}
                <div className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 p-6">
                    <h2 className="text-lg font-semibold text-gray-900 dark:text-white mb-6 flex items-center gap-2">
                        <Lock className="w-5 h-5 text-blue-500" />
                        Security
                    </h2>

                    <form onSubmit={handlePasswordChange} className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Current Password</label>
                            <div className="relative">
                                <input
                                    type="password"
                                    value={currentPassword}
                                    onChange={(e) => setCurrentPassword(e.target.value)}
                                    className="w-full rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-900 dark:text-white px-4 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-colors"
                                    required
                                />
                            </div>
                        </div>

                        <div className="pt-2">
                            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">New Password</label>
                            <div className="relative">
                                <input
                                    type="password"
                                    value={newPassword}
                                    onChange={(e) => setNewPassword(e.target.value)}
                                    className="w-full rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-900 dark:text-white px-4 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-colors"
                                    required
                                    minLength={8}
                                />
                                <p className="mt-1 text-xs text-gray-500 dark:text-gray-400">Must be at least 8 characters long</p>
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Confirm New Password</label>
                            <div className="relative">
                                <input
                                    type="password"
                                    value={confirmPassword}
                                    onChange={(e) => setConfirmPassword(e.target.value)}
                                    className="w-full rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-900 dark:text-white px-4 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-colors"
                                    required
                                />
                            </div>
                        </div>

                        <div className="pt-4">
                            <button
                                type="submit"
                                disabled={passwordSaving}
                                className="w-full flex items-center justify-center gap-2 bg-gray-900 hover:bg-gray-800 dark:bg-gray-700 dark:hover:bg-gray-600 text-white font-medium py-2.5 px-4 rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                {passwordSaving ? (
                                    <>
                                        <Loader2 className="w-5 h-5 animate-spin" />
                                        Updating Password...
                                    </>
                                ) : (
                                    <>
                                        <Lock className="w-5 h-5" />
                                        Update Password
                                    </>
                                )}
                            </button>
                        </div>
                    </form>
                </div>
            </div>
        </div>
    );
};

export default Account;

import { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import {
    Users,
    Plus,
    Search,
    Filter,
    Edit2,
    Trash2,
    X,
    Save,
    Phone,
    Mail,
    MapPin,
    Gauge,
    UserCircle,
    Building2,
    Activity,
    ChevronDown
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

import Swal from 'sweetalert2';
import DashboardLoader from '@/lib/loader';
import { useOutletContext } from 'react-router-dom';

interface Meter {
    id: string;
    meter_number: string;
}

interface Vendor {
    id: string;
    business_name: string;
}

interface Customer {
    id: string;
    vendor_id: string;
    meter_id: string;
    name: string;
    phone: string;
    email: string | null;
    address: string | null;
    status: 'active' | 'inactive';
    vendor?: Vendor;
    meter?: Meter;
}

interface User {
    id: string;
    name: string;
    role: string;
}

const Customers = () => {
    const { user } = useOutletContext<{ user: User }>();
    const isAdmin = user.role === 'admin' || user.role === 'system_admin';

    const [customers, setCustomers] = useState<Customer[]>([]);
    const [availableMeters, setAvailableMeters] = useState<Meter[]>([]);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);
    const [editingCustomer, setEditingCustomer] = useState<Customer | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [formData, setFormData] = useState({
        name: '',
        phone: '',
        email: '',
        address: '',
        meter_id: '',
        status: 'active'
    });

    const API_URL = import.meta.env.VITE_API_URL;

    const fetchCustomers = useCallback(async () => {
        try {
            const token = localStorage.getItem('token');
            const response = await axios.get(`${API_URL}/admin/customers?search=${searchTerm}`, {
                headers: { Authorization: `Bearer ${token}` }
            });
            setCustomers(response.data.data);
        } catch (error) {
            console.error('Failed to fetch customers', error);
            Swal.fire({
                icon: 'error',
                title: 'Error',
                text: 'Failed to load customers',
                toast: true,
                position: 'top-end',
                showConfirmButton: false,
                timer: 3000
            });
        } finally {
            setLoading(false);
        }
    }, [API_URL, searchTerm]);

    const fetchMeters = useCallback(async () => {
        try {
            const token = localStorage.getItem('token');
            const response = await axios.get(`${API_URL}/admin/meters?per_page=100`, {
                headers: { Authorization: `Bearer ${token}` }
            });
            setAvailableMeters(response.data.data);
        } catch (error) {
            console.error('Failed to fetch meters', error);
        }
    }, [API_URL]);

    useEffect(() => {
        fetchCustomers();
        fetchMeters();
    }, [fetchCustomers, fetchMeters]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            const token = localStorage.getItem('token');
            if (editingCustomer) {
                await axios.put(`${API_URL}/admin/customers/${editingCustomer.id}`, formData, {
                    headers: { Authorization: `Bearer ${token}` }
                });
                Swal.fire({
                    icon: 'success',
                    title: 'Success',
                    text: 'Customer updated successfully',
                    toast: true,
                    position: 'top-end',
                    showConfirmButton: false,
                    timer: 3000
                });
            } else {
                await axios.post(`${API_URL}/admin/customers`, formData, {
                    headers: { Authorization: `Bearer ${token}` }
                });
                Swal.fire({
                    icon: 'success',
                    title: 'Success',
                    text: 'Customer registered successfully',
                    toast: true,
                    position: 'top-end',
                    showConfirmButton: false,
                    timer: 3000
                });
            }
            setShowModal(false);
            fetchCustomers();
        } catch (error: any) {
            Swal.fire({
                icon: 'error',
                title: 'Error',
                text: error.response?.data?.message || 'Action failed',
                toast: true,
                position: 'top-end',
                showConfirmButton: false,
                timer: 3000
            });
        }
    };

    const handleDelete = async (id: string) => {
        const isDarkMode = document.documentElement.classList.contains('dark');
        const result = await Swal.fire({
            title: 'Unregister Customer?',
            text: "This will remove the customer and their link to the meter.",
            icon: 'warning',
            showCancelButton: true,
            confirmButtonColor: '#ef4444',
            confirmButtonText: 'Yes, remove',
            background: isDarkMode ? '#0f172a' : '#fff',
            color: isDarkMode ? '#fff' : '#000'
        });

        if (result.isConfirmed) {
            try {
                const token = localStorage.getItem('token');
                await axios.delete(`${API_URL}/admin/customers/${id}`, {
                    headers: { Authorization: `Bearer ${token}` }
                });
                Swal.fire({
                    icon: 'success',
                    title: 'Removed',
                    text: 'Customer removed',
                    toast: true,
                    position: 'top-end',
                    showConfirmButton: false,
                    timer: 3000
                });
                fetchCustomers();
            } catch (error) {
                Swal.fire({
                    icon: 'error',
                    title: 'Error',
                    text: 'Deletion failed',
                    toast: true,
                    position: 'top-end',
                    showConfirmButton: false,
                    timer: 3000
                });
            }
        }
    };

    const openModal = (customer: Customer | null = null) => {
        if (customer) {
            setEditingCustomer(customer);
            setFormData({
                name: customer.name,
                phone: customer.phone,
                email: customer.email || '',
                address: customer.address || '',
                meter_id: customer.meter_id,
                status: customer.status
            });
        } else {
            setEditingCustomer(null);
            setFormData({
                name: '',
                phone: '',
                email: '',
                address: '',
                meter_id: '',
                status: 'active'
            });
        }
        setShowModal(true);
    };

    if (loading) return <DashboardLoader title="Loading Contacts" subtitle="Preparing customer directory..." />;

    return (
        <div className="p-6 md:p-8 min-h-screen bg-slate-50 dark:bg-slate-950 transition-colors">
            {/* Header */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 mb-10">
                <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }}>
                    <div className="flex items-center gap-3 mb-2 text-indigo-600 dark:text-indigo-400">
                        <div className="p-2 bg-indigo-50 dark:bg-indigo-900/30 rounded-xl">
                            <Users size={24} />
                        </div>
                        <span className="font-bold tracking-widest uppercase text-xs">CRM</span>
                    </div>
                    <h1 className="text-4xl font-black text-slate-900 dark:text-white tracking-tight">
                        Customer <span className="text-indigo-600 dark:text-indigo-400">Directory</span>
                    </h1>
                    <p className="mt-2 text-slate-500 dark:text-slate-400 max-w-xl">
                        {isAdmin ? 'Complete system-wide customer registry across all vendor networks.' : 'Manage your business clients and their meter connections.'}
                    </p>
                </motion.div>

                <motion.button
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.98 }}
                    onClick={() => openModal()}
                    className="group flex items-center gap-3 bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-4 rounded-2xl font-bold shadow-lg shadow-indigo-500/20 transition-all font-sans"
                >
                    <Plus size={20} className="group-hover:rotate-90 transition-transform duration-300" />
                    Register Client
                </motion.button>
            </div>

            {/* Main Content Area */}
            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden">
                {/* Table Header Controls */}
                <div className="p-6 md:p-8 border-b border-slate-100 dark:border-slate-800 flex flex-col md:flex-row gap-6">
                    <div className="flex-1 relative group">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-indigo-500 transition-colors" size={20} />
                        <input
                            type="text"
                            placeholder="Search by name, phone, or email..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full bg-slate-50 dark:bg-slate-950 border border-slate-100 dark:border-slate-800 rounded-2xl py-4 pl-12 pr-4 text-slate-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                        />
                    </div>
                    <div className="flex gap-4">
                        <button className="px-6 py-4 bg-slate-50 dark:bg-slate-950 border border-slate-100 dark:border-slate-800 rounded-2xl text-slate-600 dark:text-slate-400 font-bold hover:bg-white dark:hover:bg-slate-900 transition-all flex items-center gap-2">
                            <Filter size={18} />
                            All Roles
                            <ChevronDown size={14} />
                        </button>
                    </div>
                </div>

                {/* Table Container */}
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-slate-50/50 dark:bg-slate-800/20 px-8">
                                <th className="py-5 px-8 text-xs font-black text-slate-400 uppercase tracking-widest border-b border-slate-100 dark:border-slate-800">Client Info</th>
                                <th className="py-5 px-8 text-xs font-black text-slate-400 uppercase tracking-widest border-b border-slate-100 dark:border-slate-800 text-center">Equipment</th>
                                {isAdmin && <th className="py-5 px-8 text-xs font-black text-slate-400 uppercase tracking-widest border-b border-slate-100 dark:border-slate-800">Affiliation</th>}
                                <th className="py-5 px-8 text-xs font-black text-slate-400 uppercase tracking-widest border-b border-slate-100 dark:border-slate-800 text-center">Status</th>
                                <th className="py-5 px-8 text-xs font-black text-slate-400 uppercase tracking-widest border-b border-slate-100 dark:border-slate-800 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
                            {customers.map((customer, idx) => (
                                <motion.tr
                                    key={customer.id}
                                    initial={{ opacity: 0 }}
                                    animate={{ opacity: 1 }}
                                    transition={{ delay: idx * 0.03 }}
                                    className="group hover:bg-slate-50/80 dark:hover:bg-slate-800/30 transition-colors"
                                >
                                    <td className="py-6 px-8">
                                        <div className="flex items-center gap-4">
                                            <div className="w-12 h-12 bg-indigo-50 dark:bg-indigo-900/20 rounded-2xl flex items-center justify-center text-indigo-600 dark:text-indigo-400 group-hover:scale-110 transition-transform font-bold text-lg">
                                                {customer.name.charAt(0)}
                                            </div>
                                            <div>
                                                <p className="font-black text-slate-900 dark:text-white tracking-tight leading-none mb-1">{customer.name}</p>
                                                <div className="flex items-center gap-3 text-sm text-slate-400">
                                                    <span className="flex items-center gap-1"><Phone size={12} className="text-slate-300" /> {customer.phone}</span>
                                                    {customer.email && <span className="flex items-center gap-1 opacity-60"><Mail size={12} /> {customer.email}</span>}
                                                </div>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="py-6 px-8 text-center">
                                        {customer.meter ? (
                                            <div className="inline-flex items-center gap-2 px-4 py-2 bg-slate-100 dark:bg-slate-800 rounded-xl text-slate-600 dark:text-slate-300 font-bold text-sm">
                                                <Gauge size={14} className="text-indigo-500" />
                                                SN: {customer.meter.meter_number}
                                            </div>
                                        ) : (
                                            <span className="text-xs text-slate-400 italic">No Meter Linked</span>
                                        )}
                                    </td>
                                    {isAdmin && (
                                        <td className="py-6 px-8">
                                            <div className="flex items-center gap-2 text-slate-600 dark:text-slate-400">
                                                <Building2 size={16} className="text-slate-400" />
                                                <span className="font-bold text-sm">{customer.vendor?.business_name || 'System Owned'}</span>
                                            </div>
                                        </td>
                                    )}
                                    <td className="py-6 px-8 text-center">
                                        <span className={`
inline - flex items - center gap - 1.5 px - 3 py - 1.5 rounded - full text - [10px] font - black uppercase tracking - tighter
                                            ${customer.status === 'active'
                                                ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 border border-emerald-100 dark:border-emerald-800/50'
                                                : 'bg-slate-50 dark:bg-slate-800 text-slate-400 border border-slate-100 dark:border-slate-700'
                                            }
`}>
                                            <div className={`w - 1.5 h - 1.5 rounded - full ${customer.status === 'active' ? 'bg-emerald-500 animate-pulse' : 'bg-slate-400'} `} />
                                            {customer.status}
                                        </span>
                                    </td>
                                    <td className="py-6 px-8 text-right">
                                        <div className="flex justify-end gap-2">
                                            <button
                                                onClick={() => openModal(customer)}
                                                className="p-3 text-slate-400 hover:text-indigo-600 hover:bg-white dark:hover:bg-slate-700 rounded-xl transition-all shadow-sm border border-transparent hover:border-slate-100 dark:hover:border-slate-700"
                                            >
                                                <Edit2 size={18} />
                                            </button>
                                            <button
                                                onClick={() => handleDelete(customer.id)}
                                                className="p-3 text-slate-400 hover:text-red-500 hover:bg-white dark:hover:bg-slate-700 rounded-xl transition-all shadow-sm border border-transparent hover:border-slate-100 dark:hover:border-slate-700"
                                            >
                                                <Trash2 size={18} />
                                            </button>
                                        </div>
                                    </td>
                                </motion.tr>
                            ))}
                        </tbody>
                    </table>

                    {customers.length === 0 && (
                        <div className="p-20 text-center">
                            <div className="w-20 h-20 bg-slate-50 dark:bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-6">
                                <Activity className="text-slate-200 dark:text-slate-700" size={40} />
                            </div>
                            <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-2">Clear Registry</h3>
                            <p className="text-slate-500 dark:text-slate-400 max-w-xs mx-auto">No customers found matching your current search parameters.</p>
                        </div>
                    )}
                </div>
            </div>

            {/* Modal */}
            <AnimatePresence>
                {showModal && (
                    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            onClick={() => setShowModal(false)}
                            className="absolute inset-0 bg-slate-950/60 backdrop-blur-sm"
                        />
                        <motion.div
                            initial={{ opacity: 0, scale: 0.95, y: 20 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.95, y: 20 }}
                            className="bg-white dark:bg-slate-900 w-full max-w-xl rounded-[2.5rem] shadow-2xl relative z-10 overflow-hidden border border-slate-200 dark:border-slate-800"
                        >
                            <div className="p-8 border-b border-slate-50 dark:border-slate-800 flex justify-between items-center bg-slate-50/50 dark:bg-slate-800/30">
                                <div className="flex items-center gap-4">
                                    <div className="p-3 bg-indigo-50 dark:bg-indigo-900/30 rounded-2xl text-indigo-600">
                                        <UserCircle size={28} />
                                    </div>
                                    <div>
                                        <h2 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight leading-tight">
                                            {editingCustomer ? 'Update Identity' : 'Client Registration'}
                                        </h2>
                                        <p className="text-sm text-slate-500 font-medium">Capture essential contact and location data</p>
                                    </div>
                                </div>
                                <button onClick={() => setShowModal(false)} className="p-3 hover:bg-white dark:hover:bg-slate-700 rounded-2xl transition-all text-slate-400 hover:text-red-500 shadow-sm border border-transparent hover:border-slate-100 dark:hover:border-slate-600">
                                    <X size={20} />
                                </button>
                            </div>

                            <form onSubmit={handleSubmit} className="p-8 space-y-6">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div className="md:col-span-2">
                                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Legal Name</label>
                                        <input
                                            type="text"
                                            required
                                            value={formData.name}
                                            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                            className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-800 rounded-2xl py-4 px-6 text-slate-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-bold"
                                            placeholder="John Doe"
                                        />
                                    </div>

                                    <div>
                                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Mobile Line</label>
                                        <div className="relative">
                                            <Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                                            <input
                                                type="text"
                                                required
                                                value={formData.phone}
                                                onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                                                className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-800 rounded-2xl py-4 pl-12 pr-4 text-slate-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                                                placeholder="+254..."
                                            />
                                        </div>
                                    </div>

                                    <div>
                                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Email Address (Optional)</label>
                                        <div className="relative">
                                            <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                                            <input
                                                type="email"
                                                value={formData.email}
                                                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                                className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-800 rounded-2xl py-4 pl-12 pr-4 text-slate-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                                                placeholder="email@provider.com"
                                            />
                                        </div>
                                    </div>

                                    <div className="md:col-span-2">
                                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Assigned Equipment (Meter)</label>
                                        <div className="relative">
                                            <Gauge className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                                            <select
                                                required
                                                value={formData.meter_id}
                                                onChange={(e) => setFormData({ ...formData, meter_id: e.target.value })}
                                                className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-800 rounded-2xl py-4 pl-12 pr-4 text-slate-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all appearance-none font-bold"
                                            >
                                                <option value="">Select a meter SN...</option>
                                                {availableMeters.map(m => (
                                                    <option key={m.id} value={m.id}>SN: {m.meter_number}</option>
                                                ))}
                                            </select>
                                        </div>
                                    </div>

                                    <div className="md:col-span-2">
                                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Physical Address</label>
                                        <div className="relative">
                                            <MapPin className="absolute left-4 top-[1.1rem] text-slate-400" size={18} />
                                            <textarea
                                                rows={2}
                                                value={formData.address}
                                                onChange={(e) => setFormData({ ...formData, address: e.target.value })}
                                                className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-800 rounded-2xl py-4 pl-12 pr-4 text-slate-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all resize-none"
                                                placeholder="Building, Street, Area..."
                                            />
                                        </div>
                                    </div>
                                </div>

                                <div className="pt-6 flex gap-4">
                                    <button
                                        type="button"
                                        onClick={() => setShowModal(false)}
                                        className="flex-1 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 font-black py-4 rounded-2xl hover:bg-slate-200 dark:hover:bg-slate-700 transition-all uppercase text-xs tracking-widest"
                                    >
                                        Discard
                                    </button>
                                    <button
                                        type="submit"
                                        className="flex-[2] bg-indigo-600 hover:bg-indigo-700 text-white font-black py-4 rounded-2xl shadow-lg shadow-indigo-500/20 flex items-center justify-center gap-3 transition-all uppercase text-xs tracking-widest"
                                    >
                                        <Save size={18} />
                                        {editingCustomer ? 'Update Profile' : 'Confirm Registration'}
                                    </button>
                                </div>
                            </form>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>
        </div>
    );
};

export default Customers;

import { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import { 
    Gauge, 
    Plus, 
    Search, 
    Filter, 
    Edit2, 
    Trash2, 
    X, 
    Save, 
    Building2, 
    DollarSign, 
    AlertCircle, 
    Activity, 
    ChevronRight, 
    ArrowUpRight,
    Zap,
    Key,
    RefreshCw,
    Settings
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

import Swal from 'sweetalert2';
import DashboardLoader from '@/lib/loader';
import { useOutletContext } from 'react-router-dom';

interface Vendor {
    id: string;
    business_name: string;
}

/** Normalize API vendor to { id, business_name } (MongoDB may return _id) */
function normalizeVendor(v: { id?: string; _id?: string; business_name?: string }): Vendor {
    return {
        id: String(v?.id ?? v?._id ?? ''),
        business_name: String(v?.business_name ?? ''),
    };
}

interface Meter {
    id: string;
    meter_number: string;
    type: string;
    initial_reading: number;
    price_per_unit: number;
    status: 'active' | 'inactive' | 'maintenance';
    vendor_id: string | null;
    vendor?: Vendor;
}

interface User {
    id: string;
    name: string;
    role: string;
}

const Meters = () => {
    const context = useOutletContext<{ user: User }>();
    const user = context?.user;

    if (!user) return <DashboardLoader />;

    const isAdmin = user.role === 'admin' || user.role === 'system_admin';

    const [meters, setMeters] = useState<Meter[]>([]);
    const [vendors, setVendors] = useState<Vendor[]>([]);
    const [loading, setLoading] = useState(true);
    const [metersFetchError, setMetersFetchError] = useState<string | null>(null);
    const [showModal, setShowModal] = useState(false);
    const [editingMeter, setEditingMeter] = useState<Meter | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [formData, setFormData] = useState({
        meter_number: '',
        type: 'electricity',
        initial_reading: '0',
        price_per_unit: '0',
        vendor_id: '',
        status: 'active',
        sgc: '201457',
        krn: '1',
        ti: '1',
        ea: '7',
        ken: '255'
    });

    const API_URL = import.meta.env.VITE_API_URL;

    const fetchMeters = useCallback(async () => {
        setMetersFetchError(null);
        const token = localStorage.getItem('token');
        if (!token) {
            setLoading(false);
            setMetersFetchError('Not signed in');
            return;
        }
        try {
            setLoading(true);
            const response = await axios.get(
                `${API_URL}/admin/meters?search=${searchTerm}&per_page=100`,
                { headers: { Authorization: `Bearer ${token}` } }
            );
            const list = response.data?.data ?? (Array.isArray(response.data) ? response.data : []);
            setMeters(Array.isArray(list) ? list : []);
        } catch (error: unknown) {
            console.error('Failed to fetch meters', error);
            const message = axios.isAxiosError(error)
                ? (error.response?.data?.message || error.message || 'Failed to load meters')
                : 'Failed to load meters';
            setMetersFetchError(message);
            Swal.fire({
                icon: 'error',
                title: 'Error',
                text: 'Failed to load meters',
                toast: true,
                position: 'top-end',
                showConfirmButton: false,
                timer: 3000
            });
        } finally {
            setLoading(false);
        }
    }, [API_URL, searchTerm]);

    const fetchVendors = useCallback(async () => {
        const token = localStorage.getItem('token');
        if (!token) return;
        try {
            const response = await axios.get(`${API_URL}/admin/vendors?per_page=100`, {
                headers: { Authorization: `Bearer ${token}` }
            });
            // Laravel paginator: { data: [...], current_page, ... }; fallback to raw array
            const raw =
                response.data?.data ??
                (Array.isArray(response.data) ? response.data : []);
            const list = Array.isArray(raw)
                ? raw.map(normalizeVendor).filter((v) => v.id)
                : [];
            setVendors(list);
        } catch (error) {
            console.error('Failed to fetch vendors', error);
            Swal.fire({
                icon: 'error',
                title: 'Error',
                text: 'Failed to load vendors list',
                toast: true,
                position: 'top-end',
                showConfirmButton: false,
                timer: 3000
            });
            setVendors([]);
        }
    }, [API_URL]);

    useEffect(() => {
        fetchMeters();
    }, [fetchMeters]);

    // Fetch available vendors on load (for admin assign dropdown)
    useEffect(() => {
        fetchVendors();
    }, [fetchVendors]);

    // When admin opens the modal, refetch vendors so the dropdown shows all current vendors
    useEffect(() => {
        if (isAdmin && showModal) fetchVendors();
    }, [isAdmin, showModal, fetchVendors]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            const token = localStorage.getItem('token');
            const payload: Record<string, unknown> = {
                meter_number: formData.meter_number,
                type: formData.type,
                initial_reading: parseFloat(formData.initial_reading),
                vendor_id: formData.vendor_id || null,
                status: formData.status,
                sgc: parseInt(formData.sgc || '201457', 10),
                krn: parseInt(formData.krn || '1', 10),
                ti: parseInt(formData.ti || '1', 10),
                ea: parseInt(formData.ea || '7', 10),
                ken: parseInt(formData.ken || '255', 10)
            };
            // Only vendors can set pricing; admin must not send price_per_unit
            if (!isAdmin) {
                payload.price_per_unit = parseFloat(formData.price_per_unit);
            }

            if (editingMeter) {
                await axios.put(`${API_URL}/admin/meters/${editingMeter.id}`, payload, {
                    headers: { Authorization: `Bearer ${token}` }
                });
                Swal.fire({
                    icon: 'success',
                    title: 'Success',
                    text: 'Meter updated successfully',
                    toast: true,
                    position: 'top-end',
                    showConfirmButton: false,
                    timer: 3000
                });
            } else {
                await axios.post(`${API_URL}/admin/meters`, payload, {
                    headers: { Authorization: `Bearer ${token}` }
                });
                Swal.fire({
                    icon: 'success',
                    title: 'Success',
                    text: 'Meter created successfully',
                    toast: true,
                    position: 'top-end',
                    showConfirmButton: false,
                    timer: 3000
                });
            }
            setShowModal(false);
            fetchMeters();
        } catch (error: any) {
            Swal.fire({
                icon: 'error',
                title: 'Error',
                text: error.response?.data?.message || 'Action failed',
                toast: true,
                position: 'top-end',
                showConfirmButton: false,
                timer: 3000
            });
        }
    };

    const handleDelete = async (id: string) => {
        const isDarkMode = document.documentElement.classList.contains('dark');
        const result = await Swal.fire({
            title: 'Delete Meter?',
            text: "This will permanently remove this meter and its history.",
            icon: 'warning',
            showCancelButton: true,
            confirmButtonColor: '#ef4444',
            confirmButtonText: 'Yes, delete it',
            background: isDarkMode ? '#0f172a' : '#fff',
            color: isDarkMode ? '#fff' : '#000'
        });

        if (result.isConfirmed) {
            try {
                const token = localStorage.getItem('token');
                await axios.delete(`${API_URL}/admin/meters/${id}`, {
                    headers: { Authorization: `Bearer ${token}` }
                });
                Swal.fire({
                    icon: 'success',
                    title: 'Deleted',
                    text: 'Meter deleted',
                    toast: true,
                    position: 'top-end',
                    showConfirmButton: false,
                    timer: 3000
                });
                fetchMeters();
            } catch (error) {
                Swal.fire({
                    icon: 'error',
                    title: 'Error',
                    text: 'Failed to delete meter',
                    toast: true,
                    position: 'top-end',
                    showConfirmButton: false,
                    timer: 3000
                });
            }
        }
    };

    const openModal = (meter: Meter | null = null) => {
        if (meter) {
            setEditingMeter(meter);
            setFormData({
                meter_number: meter.meter_number,
                type: meter.type,
                initial_reading: meter.initial_reading.toString(),
                price_per_unit: meter.price_per_unit.toString(),
                vendor_id: meter.vendor_id || '',
                status: meter.status,
                sgc: (meter as any).sgc?.toString() || '201457',
                krn: (meter as any).krn?.toString() || '1',
                ti: (meter as any).ti?.toString() || '1',
                ea: (meter as any).ea?.toString() || '7',
                ken: (meter as any).ken?.toString() || '255'
            });
        } else {
            setEditingMeter(null);
            setFormData({
                meter_number: '',
                type: 'electricity',
                initial_reading: '0',
                price_per_unit: '0',
                vendor_id: '',
                status: 'active',
                sgc: '201457',
                krn: '1',
                ti: '1',
                ea: '7',
                ken: '255'
            });
        }
        setShowModal(true);
    };

    if (loading) return <DashboardLoader title="Loading Equipment" subtitle="Syncing meter data..." />;

    return (
        <div className="p-6 md:p-8 min-h-screen bg-gray-50 dark:bg-gray-950 transition-colors">
            {/* Header Area */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-10">
                <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }}>
                    <div className="flex items-center gap-3 mb-2">
                        <div className="p-3 bg-gradient-to-br from-indigo-100 to-indigo-50 dark:from-indigo-900/80 dark:to-indigo-900/30 border border-indigo-200/50 dark:border-indigo-800/50 rounded-2xl shrink-0 shadow-sm">
                            <Gauge className="w-6 h-6 text-indigo-600 dark:text-indigo-400" />
                        </div>
                        <span className="text-[10px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-[0.2em]">
                            {isAdmin ? 'Infrastructure Directory' : 'Hardware Asset Registry'}
                        </span>
                    </div>
                    <h1 className="text-3xl font-black text-gray-900 dark:text-white tracking-tight">
                        {isAdmin ? 'Meter Infrastructure' : 'My Meter Asset Registry'}
                    </h1>
                    <p className="mt-2 text-sm text-gray-500 dark:text-gray-400 max-w-xl font-medium">
                        {isAdmin
                            ? 'Monitor, assign, and manage vending equipment across your vendor network.'
                            : 'Monitor your assigned hardware units and manage unit pricing for end-users.'}
                    </p>
                </motion.div>

                {isAdmin && (
                    <motion.button
                        whileHover={{ scale: 1.02, y: -2 }}
                        whileTap={{ scale: 0.98 }}
                        onClick={() => openModal()}
                        className="
                            group flex items-center gap-2
                            bg-gray-900 dark:bg-white text-white dark:text-gray-900
                            px-6 py-3
                            rounded-2xl
                            font-black text-xs uppercase tracking-widest
                            shadow-xl shadow-gray-200 dark:shadow-none
                            transition-all duration-300
                            hover:shadow-indigo-500/10
                        "
                    >
                        <Plus size={18} className="group-hover:rotate-90 transition-transform duration-300" />
                        <span>Provision Hardware</span>
                    </motion.button>
                )}
            </div>

            {/* Controls Area */}
            <div className="grid grid-cols-1 lg:grid-cols-4 gap-4 mb-8">
                <div className="lg:col-span-3 relative group">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 dark:text-gray-500 group-focus-within:text-indigo-500 transition-colors" size={18} />
                    <input
                        type="text"
                        placeholder="Search system by meter serial number..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full bg-white dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-2xl py-3.5 pl-12 pr-4 text-gray-900 dark:text-white focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none transition-all shadow-sm font-medium"
                    />
                </div>
                <div className="flex gap-3">
                    <button className="flex-1 flex items-center justify-center gap-2 bg-white dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-2xl py-3.5 px-4 font-black text-[10px] uppercase tracking-widest text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 transition-all shadow-sm">
                        <Filter size={16} />
                        Filter
                    </button>
                    <button onClick={fetchMeters} className="p-3.5 bg-white dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-2xl text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 transition-all shadow-sm">
                        <Activity size={18} />
                    </button>
                </div>
            </div>

            {/* Error state: fetch failed */}
            {metersFetchError && !loading && (
                <motion.div
                    initial={{ opacity: 0, scale: 0.98 }}
                    animate={{ opacity: 1, scale: 1 }}
                    className="col-span-full bg-red-50/50 dark:bg-red-950/20 border border-red-100 dark:border-red-900/30 rounded-3xl p-16 text-center backdrop-blur-sm"
                >
                    <div className="w-20 h-20 mx-auto mb-6 rounded-2xl bg-white dark:bg-red-900/30 flex items-center justify-center shadow-sm">
                        <AlertCircle className="w-10 h-10 text-red-600 dark:text-red-400" />
                    </div>
                    <h3 className="text-2xl font-black text-gray-900 dark:text-white tracking-tight mb-2">Systems Interrupted</h3>
                    <p className="text-gray-500 dark:text-gray-400 max-w-md mx-auto mb-8 font-medium">
                        {metersFetchError}
                    </p>
                    <button
                        type="button"
                        onClick={() => fetchMeters()}
                        className="inline-flex items-center gap-2 bg-gray-900 dark:bg-white text-white dark:text-gray-900 font-black text-[10px] uppercase tracking-widest px-8 py-3.5 rounded-2xl shadow-xl shadow-gray-200 dark:shadow-none transition-all active:scale-[0.98]"
                    >
                        <RefreshCw size={14} />
                        Re-initialize Sync
                    </button>
                </motion.div>
            )}

            {/* Empty state for vendors with no assigned meters */}
            {!isAdmin && meters.length === 0 && !loading && !metersFetchError && (
                <motion.div
                    initial={{ opacity: 0, scale: 0.98 }}
                    animate={{ opacity: 1, scale: 1 }}
                    className="col-span-full bg-white dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-[32px] p-16 text-center shadow-sm"
                >
                    <div className="w-20 h-20 mx-auto mb-6 rounded-2xl bg-gray-50 dark:bg-gray-800 flex items-center justify-center">
                        <Gauge className="w-10 h-10 text-gray-300" />
                    </div>
                    <h3 className="text-2xl font-black text-gray-900 dark:text-white tracking-tight mb-2">No Assets Detected</h3>
                    <p className="text-gray-500 dark:text-gray-400 max-w-md mx-auto mb-8 font-medium">
                        Your account has no assigned hardware units. Contact the system administrator to provision assets to your directory.
                    </p>
                    <button
                        type="button"
                        onClick={() => fetchMeters()}
                        className="inline-flex items-center gap-2 bg-gray-100 dark:bg-gray-800 text-gray-900 dark:text-white font-black text-[10px] uppercase tracking-widest px-8 py-3.5 rounded-2xl hover:bg-gray-200 dark:hover:bg-gray-750 transition-all"
                    >
                        <RefreshCw size={14} />
                        Check for Assignments
                    </button>
                </motion.div>
            )}

            {/* Empty state for admin with no meters */}
            {isAdmin && meters.length === 0 && !loading && !metersFetchError && (
                <motion.div
                    initial={{ opacity: 0, scale: 0.98 }}
                    animate={{ opacity: 1, scale: 1 }}
                    className="col-span-full bg-white dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-[32px] p-16 text-center shadow-xl shadow-gray-200/50 dark:shadow-none"
                >
                    <div className="w-24 h-24 mx-auto mb-8 rounded-[32px] bg-indigo-50 dark:bg-indigo-900/30 flex items-center justify-center">
                        <Gauge className="w-12 h-12 text-indigo-600 dark:text-indigo-400" />
                    </div>
                    <h3 className="text-2xl font-black text-gray-900 dark:text-white tracking-tight mb-2">Infrastructure Empty</h3>
                    <p className="text-gray-500 dark:text-gray-400 max-w-md mx-auto mb-10 font-medium">
                        You haven't provisioned any hardware units to the network yet. Create your first meter to begin distribution.
                    </p>
                    <button
                        type="button"
                        onClick={() => openModal()}
                        className="group inline-flex items-center gap-3 bg-gray-900 dark:bg-white text-white dark:text-gray-900 font-black text-[10px] uppercase tracking-[0.2em] px-10 py-4 rounded-[20px] shadow-2xl shadow-indigo-500/20 transition-all hover:translate-y-[-2px]"
                    >
                        <Plus size={18} className="group-hover:rotate-180 transition-transform duration-500" />
                        Provision Initial Unit
                    </button>
                </motion.div>
            )}

            {/* Meter Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
                <AnimatePresence mode="popLayout">
                    {meters.map((meter, index) => (
                        <motion.div
                            key={meter.id}
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.9 }}
                            transition={{ delay: Math.min(index * 0.05, 0.3) }}
                            className="bg-white dark:bg-gray-900 border border-gray-100 dark:border-gray-800 rounded-2xl p-5 shadow-sm hover:shadow-xl hover:translate-y-[-4px] transition-all relative overflow-hidden group"
                        >
                            <div className="flex justify-between items-start mb-4 relative z-10">
                                <div className="p-2.5 bg-gray-50 dark:bg-gray-800 rounded-xl group-hover:bg-indigo-50 dark:group-hover:bg-indigo-900/30 transition-colors">
                                    <Gauge className="text-gray-400 group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors" size={20} />
                                </div>
                                <div className="flex gap-2">
                                    <button
                                        onClick={() => openModal(meter)}
                                        className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 dark:hover:bg-indigo-900/40 rounded-xl transition-all"
                                    >
                                        <Edit2 size={18} />
                                    </button>
                                    {isAdmin && (
                                        <button
                                            onClick={() => handleDelete(meter.id)}
                                            className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/40 rounded-xl transition-all"
                                        >
                                            <Trash2 size={18} />
                                        </button>
                                    )}
                                </div>
                            </div>

                            <div className="space-y-4 mb-4 relative z-10">
                                <div>
                                    <p className="text-[10px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest mb-1">SN: {meter.meter_number}</p>
                                    <h3 className="text-lg font-black text-gray-900 dark:text-white normal tracking-tighter">
                                        Hardware Unit
                                    </h3>
                                    <div className="flex items-center gap-2 mt-2">
                                        <span className={`px-2 py-0.5 rounded-md text-[8px] font-black uppercase tracking-widest border ${
                                            meter.status === 'active' 
                                                ? 'bg-emerald-50 text-emerald-600 border-emerald-100 dark:bg-emerald-900/30 dark:text-emerald-400 dark:border-emerald-800' 
                                                : 'bg-amber-50 text-amber-600 border-amber-100 dark:bg-amber-900/30 dark:text-amber-400 dark:border-amber-800'
                                        }`}>
                                            {meter.status}
                                        </span>
                                        <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest bg-gray-50 dark:bg-gray-800 px-2 py-0.5 rounded-md border border-gray-100 dark:border-gray-700">
                                            {meter.type}
                                        </span>
                                    </div>
                                </div>

                                <div className="grid grid-cols-2 gap-4 pt-4 border-t border-gray-50 dark:border-gray-800">
