                                                <ShieldCheck className="w-4 h-4" />
                                            )}
                                            <span>{editingVendor ? 'Save Changes' : 'Complete Registration'}</span>
                                        </button>
                                    </div>
                                </div>
                            </form>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>
        </div>
    );
};

