export default Dashboard;

import { useEffect, useMemo, useState } from "react";
import axios from "axios";
import {
    Search,
    ChevronLeft,
    ChevronRight,
    Activity,
    RefreshCw,
    Loader2,
    Calendar,
    Monitor,
} from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import DashboardLoader from "@/lib/loader";

// --- Types ---
type TabType = 'logs' | 'communications' | 'tasks' | 'attendances';

interface AuditLogDto {
    id: number;
    user_id: number | null;
    action: string;
    description: string;
    details: any;
    ip_address: string;
    user_agent: string;
    created_at: string;
    user?: {
        name: string;
        member?: { full_name: string; e_kanisa_number: string; }
    };
}

interface CommunicationDto {
    id: number;
    title: string;
    message: string;
    type: string;
    sent_by: number;
    created_at: string;
    sender?: { full_name: string; role: string; };
    group?: { name: string; };
}

interface TaskDto {
    id: number;
    action: string;
    status: string;
    due_date?: string;
    created_at: string;
    minute?: { title: string; };
}

interface AttendanceDto {
    id: number;
    event_type: string;
    event_date: string;
    scanned_at?: string;
    created_at: string;
    member?: { full_name: string; e_kanisa_number: string; };
}

// --- Helpers ---
const getActionStyle = (action: string) => {
    const a = action.toLowerCase();
    if (a.includes('create') || a.includes('add')) return { bg: "bg-emerald-100 dark:bg-emerald-900/30", text: "text-emerald-800 dark:text-emerald-400", border: "border-emerald-200 dark:border-emerald-800/50", icon: "plus" };
    if (a.includes('update') || a.includes('edit')) return { bg: "bg-blue-100 dark:bg-blue-900/30", text: "text-blue-800 dark:text-blue-400", border: "border-blue-200 dark:border-blue-800/50", icon: "edit" };
    if (a.includes('delete') || a.includes('remove')) return { bg: "bg-red-100 dark:bg-red-900/30", text: "text-red-800 dark:text-red-400", border: "border-red-200 dark:border-red-800/50", icon: "trash" };
    if (a.includes('login') || a.includes('auth')) return { bg: "bg-purple-100 dark:bg-purple-900/30", text: "text-purple-800 dark:text-purple-400", border: "border-purple-200 dark:border-purple-800/50", icon: "lock" };
    return { bg: "bg-slate-100 dark:bg-slate-800", text: "text-slate-800 dark:text-slate-300", border: "border-slate-200 dark:border-slate-700", icon: "activity" };
};

const getCommStyle = (type: string) => {
    if (type === 'broadcast') return { bg: "bg-orange-100 dark:bg-orange-900/30", text: "text-orange-900 dark:text-orange-400", label: "Broadcast" };
    if (type === 'group') return { bg: "bg-indigo-100 dark:bg-indigo-900/30", text: "text-indigo-900 dark:text-indigo-400", label: "Group" };
    return { bg: "bg-blue-100 dark:bg-blue-900/30", text: "text-blue-900 dark:text-blue-400", label: "Individual" };
};

// --- Main Component ---
const AuditLogsPage = () => {
    const API_URL = import.meta.env.VITE_API_URL;
    const [activeTab, setActiveTab] = useState<TabType>('logs');
    const [query, setQuery] = useState("");
    const [page, setPage] = useState(1);
    const [loading, setLoading] = useState(true);
    const [data, setData] = useState<any[]>([]);
    const [total, setTotal] = useState(0);
    const [perPage] = useState(20);

    const token = useMemo(() => (typeof window !== "undefined" ? localStorage.getItem("token") : null), []);

    const fetchData = async () => {
        if (!token) return;
        setLoading(true);
        try {
            let endpoint = '/admin/audit-logs';
            if (activeTab === 'communications') endpoint = '/admin/audit-logs/communications';
            if (activeTab === 'tasks') endpoint = '/admin/audit-logs/tasks';
            if (activeTab === 'attendances') endpoint = '/admin/audit-logs/attendances';

            const url = `${API_URL}${endpoint}?search=${encodeURIComponent(query)}&page=${page}&per_page=${perPage}`;
            const res = await axios.get(url, { headers: { Authorization: `Bearer ${token}` } });

            const responseData = res.data as any;
            const pagination = responseData.data;
            const items = Array.isArray(pagination) ? pagination : (pagination?.data || []);

            setData(items);
            setTotal(pagination?.total || items.length);
        } catch (e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        setPage(1);
        fetchData();
    }, [activeTab]);

    useEffect(() => {
        const handler = setTimeout(() => fetchData(), 400);
        return () => clearTimeout(handler);
    }, [query, page]);

    // Formatters
    const formatDate = (date: string) => new Date(date).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' });
    const formatTime = (date: string) => new Date(date).toLocaleTimeString(undefined, { hour: '2-digit', minute: '2-digit' });

    // Renderers
    const renderLogs = (log: AuditLogDto) => {
        const style = getActionStyle(log.action);
        return (
            <div className="flex flex-col md:flex-row gap-5 items-start">
                <div className={`w-10 h-10 rounded-xl flex-shrink-0 flex items-center justify-center ${style.bg} ${style.text}`}>
                    <Activity className="w-5 h-5" />
                </div>
                <div className="flex-grow w-full">
                    <div className="flex justify-between items-start mb-1">
                        <h3 className="font-bold text-slate-900 dark:text-slate-100">{log.action}</h3>
                        <span className="text-xs text-slate-400 dark:text-slate-500 whitespace-nowrap">{formatDate(log.created_at)} {formatTime(log.created_at)}</span>
                    </div>
                    <p className="text-sm text-slate-600 dark:text-slate-400 mb-2">{log.description}</p>
                    {log.details && (
                        <div className="text-[10px] bg-slate-50 dark:bg-slate-950 p-2 rounded border border-slate-200 dark:border-slate-800 font-mono text-slate-500 dark:text-slate-400 overflow-x-auto max-h-32 overflow-y-auto custom-scrollbar">
                            {typeof log.details === 'object' ? JSON.stringify(log.details, null, 2).replace(/[{},"]/g, '').trim() : String(log.details)}
                        </div>
                    )}
                    <div className="mt-2 text-xs text-slate-400 flex items-center gap-2">
                        <span className="font-bold text-slate-500 dark:text-slate-300">{log.user?.member?.full_name || log.user?.name || 'System'}</span>
                        <span className="dark:text-slate-700">•</span>
                        <span className="font-mono">{log.ip_address}</span>
                    </div>
                </div>
            </div>
        );
    };

    const renderComm = (comm: CommunicationDto) => {
        const style = getCommStyle(comm.type);
        return (
            <div className="flex gap-4">
                <div className={`w-10 h-10 rounded-full flex-shrink-0 flex items-center justify-center ${style.bg} ${style.text}`}>
                    <span className="font-bold text-xs">{style.label[0]}</span>
                </div>
                <div className="flex-grow">
                    <div className="flex justify-between mb-1">
                        <div className="flex items-center gap-2">
                            <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase ${style.bg} ${style.text}`}>{style.label}</span>
                            <span className="font-bold text-slate-900 dark:text-slate-100">{comm.title || 'No Subject'}</span>
                        </div>
                        <span className="text-xs text-slate-400 dark:text-slate-500">{formatDate(comm.created_at)}</span>
                    </div>
                    <p className="text-sm text-slate-600 dark:text-slate-400 line-clamp-3 mb-2">{comm.message}</p>
                    <div className="text-xs text-slate-500 dark:text-slate-400">
                        From: <span className="font-bold text-slate-700 dark:text-slate-300">{comm.sender?.full_name || 'System'}</span> {comm.group && `• To: ${comm.group.name}`}
                    </div>
                </div>
            </div>
        );
    };

    const renderTask = (task: TaskDto) => {
        const isDone = task.status === 'Done' || task.status === 'Completed';
        return (
            <div className="flex gap-4 items-center">
                <div className={`w-1.5 rounded-full h-12 ${isDone ? 'bg-emerald-500' : 'bg-amber-400'}`} />
                <div className="flex-grow">
                    <div className="flex justify-between">
                        <h4 className={`font-bold ${isDone ? 'text-slate-500 dark:text-slate-500 line-through' : 'text-slate-900 dark:text-slate-100'}`}>{task.action}</h4>
                        <span className={`text-[10px] font-bold px-2 py-1 rounded ${isDone ? 'bg-emerald-100 dark:bg-emerald-900/30 text-emerald-800 dark:text-emerald-400' : 'bg-amber-100 dark:bg-amber-900/30 text-amber-800 dark:text-amber-400'}`}>
                            {task.status}
                        </span>
                    </div>
                    <div className="text-xs text-slate-500 dark:text-slate-400 mt-1 flex items-center gap-2">
                        <span>Minute: {task.minute?.title || 'Unknown'}</span>
                        {task.due_date && (
                            <span className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 px-1.5 py-0.5 rounded text-slate-600 dark:text-slate-300">
                                <Calendar className="w-3 h-3" /> {formatDate(task.due_date)}
                            </span>
                        )}
                    </div>
                </div>
            </div>
        );
    };

    const renderAttendance = (att: AttendanceDto) => {
        const isScanned = !!att.scanned_at;
        return (
            <div className="flex items-center gap-4">
                <div className={`p-2.5 rounded-xl ${isScanned ? 'bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-400' : 'bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400'}`}>
                    {isScanned ? <Monitor className="w-5 h-5" /> : <Calendar className="w-5 h-5" />}
                </div>
                <div className="flex-grow">
                    <div className="flex justify-between items-start">
                        <div className="font-bold text-slate-900 dark:text-slate-100">{att.member?.full_name || 'Unknown Member'}</div>
                        {isScanned && (
                            <div className="text-[10px] bg-blue-50 dark:bg-blue-900/40 text-blue-800 dark:text-blue-300 px-2 py-1 rounded border border-blue-100 dark:border-blue-800/50 font-bold">
                                Scanned {formatTime(att.scanned_at!)}
                            </div>
                        )}
                    </div>
                    <div className="text-xs text-slate-500 dark:text-slate-400 mt-0.5">
                        {att.member?.e_kanisa_number && <span className="font-mono mr-2">#{att.member.e_kanisa_number}</span>}
                        <span>{att.event_type} • {formatDate(att.event_date)}</span>
                    </div>
                </div>
            </div>
        );
    };

    const totalPages = Math.max(1, Math.ceil(total / perPage));

    if (loading && activeTab === 'logs' && data.length === 0) {
        return (
            <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-950">
                <DashboardLoader title="Loading Activity" subtitle="Fetching system records..." />
            </div>
        );
    }

    return (
        <div className="p-6 md:p-10 bg-slate-50 dark:bg-slate-950 min-h-screen font-sans text-slate-900 dark:text-slate-100 transition-colors">
            {/* Header with Tabs */}
            <div className="flex flex-col xl:flex-row justify-between items-start xl:items-center mb-8 gap-6">
                <div>
                    <h1 className="text-2xl font-bold tracking-tight text-[#0A1F44] dark:text-white mb-1">System Activity</h1>
                    <p className="text-slate-500 dark:text-slate-400 text-sm">Global registry of all system events and records</p>
                </div>

                {/* Tabs Pilla */}
                <div className="flex overflow-x-auto bg-white dark:bg-slate-900 p-1.5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm max-w-full">
                    {(['logs', 'communications', 'tasks', 'attendances'] as TabType[]).map((tab) => (
                        <button
                            key={tab}
                            onClick={() => setActiveTab(tab)}
                            className={`px-5 py-2.5 rounded-xl text-sm font-bold transition-all whitespace-nowrap ${activeTab === tab
                                    ? 'bg-[#0A1F44] dark:bg-blue-700 text-white shadow-md transform scale-[1.02]'
                                    : 'text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-slate-700 dark:hover:text-slate-200'
                                }`}
                        >
                            {tab.charAt(0).toUpperCase() + tab.slice(1)}
                        </button>
                    ))}
                </div>
            </div>

            {/* Controls */}
            <div className="flex gap-3 mb-6">
                <div className="relative group flex-grow">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 dark:text-slate-500 w-4 h-4" />
                    <input
                        value={query}
                        onChange={e => setQuery(e.target.value)}
                        placeholder={`Search ${activeTab}...`}
                        className="pl-10 pr-4 py-2.5 w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl shadow-sm focus:ring-2 focus:ring-[#0A1F44]/10 dark:focus:ring-blue-500/20 focus:border-[#0A1F44] dark:focus:border-blue-600 outline-none transition-all text-slate-900 dark:text-slate-100 placeholder-slate-400 dark:placeholder-slate-500"
                    />
                </div>
                <button onClick={fetchData} className="p-2.5 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl hover:text-[#0A1F44] dark:hover:text-blue-400 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors shadow-sm active:scale-95">
                    {loading ? <Loader2 className="animate-spin w-5 h-5 text-slate-500 dark:text-slate-400" /> : <RefreshCw className="w-5 h-5 text-slate-500 dark:text-slate-400" />}
                </button>
            </div>

            {/* Content List */}
            <div className="space-y-4 max-w-5xl mx-auto pb-20">
                <AnimatePresence mode="wait">
                    {data.map((item, i) => (
                        <motion.div
                            key={item.id}
                            initial={{ opacity: 0, y: 15 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.98 }}
                            transition={{ delay: i * 0.03, duration: 0.2 }}
                            className="bg-white dark:bg-slate-900 rounded-2xl p-5 border border-slate-200 dark:border-slate-800 shadow-sm hover:shadow-md dark:hover:border-blue-900 transition-all cursor-default"
                        >
                            {activeTab === 'logs' && renderLogs(item)}
                            {activeTab === 'communications' && renderComm(item)}
                            {activeTab === 'tasks' && renderTask(item)}
                            {activeTab === 'attendances' && renderAttendance(item)}
                        </motion.div>
                    ))}
                </AnimatePresence>

                {!loading && data.length === 0 && (
                    <div className="flex flex-col items-center justify-center py-20 bg-white dark:bg-slate-900 rounded-3xl border border-dashed border-slate-300 dark:border-slate-700">
                        <div className="p-4 bg-slate-50 dark:bg-slate-800 rounded-full mb-4 opacity-50">
                            <Activity className="w-8 h-8 text-slate-400 dark:text-slate-600" />
                        </div>
                        <p className="text-slate-500 dark:text-slate-500 font-medium">No records found for {activeTab}</p>
                    </div>
                )}

                {/* Pagination */}
                {total > 0 && (
                    <div className="flex justify-center mt-8">
                        <div className="flex bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-slate-200 dark:border-slate-800 p-1 gap-1">
                            <button
                                onClick={() => setPage(p => Math.max(1, p - 1))}
                                disabled={page <= 1}
                                className="p-2 rounded-lg hover:bg-slate-50 dark:hover:bg-slate-800 disabled:opacity-30 text-slate-500 dark:text-slate-400 transition-colors"
                            >
                                <ChevronLeft className="w-5 h-5" />
                            </button>
                            <div className="flex items-center px-4 font-bold text-sm text-[#0A1F44] dark:text-white">
                                Page {page} of {totalPages}
                            </div>
                            <button
                                onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                                disabled={page >= totalPages}
                                className="p-2 rounded-lg hover:bg-slate-50 dark:hover:bg-slate-800 disabled:opacity-30 text-slate-500 dark:text-slate-400 transition-colors"
                            >
                                <ChevronRight className="w-5 h-5" />
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default AuditLogsPage;

import { useState } from 'react';
import axios from 'axios';
import { Smartphone, Play, AlertCircle } from 'lucide-react';
import { motion } from 'framer-motion';
import Swal from 'sweetalert2';
import { useOutletContext } from 'react-router-dom';

interface UserContext {
    user: {
        id: string;
        name: string;
        email: string;
        role: string;
    };
}

const LipaTokenNaMpesa = () => {
    const { user } = useOutletContext<UserContext>();
    const [testPhone, setTestPhone] = useState('');
    const [testAmount, setTestAmount] = useState('');
    const [testing, setTesting] = useState(false);

    const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:8000/api';

    const handleTestMpesa = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!testPhone || !testAmount) {
            Swal.fire({
                icon: 'warning',
                title: 'Missing details',
                text: 'Please enter both phone number and amount.',
                toast: true,
                position: 'top-end',
                showConfirmButton: false,
                timer: 4000,
                timerProgressBar: true,
            });
            return;
        }

        const amountNumber = Number(testAmount);
        if (isNaN(amountNumber) || amountNumber <= 0) {
            Swal.fire({
                icon: 'warning',
                title: 'Invalid amount',
                text: 'Please enter a valid amount greater than 0.',
                toast: true,
                position: 'top-end',
                showConfirmButton: false,
                timer: 4000,
                timerProgressBar: true,
            });
            return;
        }

        try {
            setTesting(true);
            const token = localStorage.getItem('token');

            const payload: any = {
                phone: testPhone,
                amount: amountNumber,
                vendor_email: user?.email || ''
            };

            const response = await axios.post(
                `${API_URL}/admin/system-config/test-mpesa`,
                payload,
                {
                    headers: {
                        Authorization: `Bearer ${token}`,
                    },
                }
            );

            if (response.data.status === 200) {
                Swal.fire({
                    icon: 'success',
                    title: 'STK Push Sent',
                    text: 'M-Pesa prompt sent. Check the phone for the payment request.',
                    toast: true,
                    position: 'top-end',
                    showConfirmButton: false,
                    timer: 4000,
                    timerProgressBar: true,
                });
            }
        } catch (error: any) {
            console.error('Error sending test M-Pesa:', error);
            Swal.fire({
                icon: 'error',
                title: 'Payment Failed',
                text: error.response?.data?.message || 'Failed to initiate M-Pesa STK push. Check your credentials in System Configuration.',
                toast: true,
                position: 'top-end',
                showConfirmButton: false,
                timer: 5000,
                timerProgressBar: true,
            });
        } finally {
            setTesting(false);
        }
    };

    return (
        <div className="p-6 md:p-8 min-h-screen bg-slate-50 dark:bg-slate-950 transition-colors flex items-center justify-center">
            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="w-full max-w-md bg-white dark:bg-slate-900 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-800 overflow-hidden"
            >
                <div className="p-6 md:p-8 bg-emerald-50 dark:bg-emerald-900/20 border-b border-emerald-100 dark:border-emerald-800/50 text-center">
                    <div className="w-16 h-16 mx-auto bg-emerald-100 dark:bg-emerald-900/50 rounded-2xl flex items-center justify-center text-emerald-600 dark:text-emerald-400 mb-4 shadow-sm">
                        <Smartphone size={32} />
                    </div>
                    <h1 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">
                        Lipa Na M-Pesa
                    </h1>
                    <p className="mt-2 text-sm text-slate-500 dark:text-slate-400">
                        Simulate a customer payment to test your STK credentials.
                    </p>
                </div>

                <form onSubmit={handleTestMpesa} className="p-6 md:p-8 space-y-5">
                    <div className="bg-amber-50 dark:bg-amber-900/20 rounded-xl p-4 flex gap-3 text-amber-700 dark:text-amber-400 text-sm">
                        <AlertCircle className="w-5 h-5 flex-shrink-0" />
                        <p>This will send a real M-Pesa prompt to the phone number below if your credentials are valid.</p>
                    </div>

                    <div>
                        <label className="block text-xs font-bold text-slate-500 mb-1.5 ml-1">M-Pesa Phone Number</label>
                        <div className="relative">
                            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 font-bold text-sm">254</span>
                            <input
                                type="text"
                                required
                                disabled={testing}
                                value={testPhone}
                                onChange={(e) => setTestPhone(e.target.value)}
                                className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl py-3 pl-12 pr-4 text-slate-900 dark:text-white focus:ring-2 focus:ring-emerald-500 outline-none transition-all disabled:opacity-50"
                                placeholder="712345678"
                            />
                        </div>
                    </div>

                    <div>
                        <label className="block text-xs font-bold text-slate-500 mb-1.5 ml-1">Test Amount (KES)</label>
                        <div className="relative">
                            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 font-bold text-sm">Ksh</span>
                            <input
                                type="number"
                                min="1"
                                step="1"
                                required
                                disabled={testing}
                                value={testAmount}
                                onChange={(e) => setTestAmount(e.target.value)}
                                className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl py-3 pl-12 pr-4 text-lg font-black text-slate-900 dark:text-white focus:ring-2 focus:ring-emerald-500 outline-none transition-all disabled:opacity-50"
                                placeholder="1"
                            />
                        </div>
                    </div>

                    <div className="pt-2">
                        <motion.button
                            whileHover={!testing ? { scale: 1.02 } : {}}
                            whileTap={!testing ? { scale: 0.98 } : {}}
                            type="submit"
                            disabled={testing || !testPhone || !testAmount}
                            className="w-full py-3.5 text-sm font-bold text-white bg-emerald-600 rounded-xl hover:bg-emerald-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors shadow-lg shadow-emerald-600/20 flex items-center justify-center gap-2"
                        >
                            {testing ? (
                                <>
                                    <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                                    <span>Initiating...</span>
                                </>
                            ) : (
                                <>
                                    <Play size={18} fill="currentColor" />
                                    <span>Send STK Push</span>
                                </>
                            )}
                        </motion.button>
                    </div>
                </form>
            </motion.div>
        </div>
    );
};

export default LipaTokenNaMpesa;

import { useState, useCallback, useEffect } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import Swal from "sweetalert2";
import { Mail, User, Lock, Eye, EyeOff, ChevronDown, CheckCircle2, Phone, Smartphone } from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import api from "@/lib/api";
import Logo from "@/assets/icon.png";
import React from "react";

type LoginMode = "email" | "kanisa" | "customer";

interface ModeOption {
  value: LoginMode;
  label: string;
  description: string;
  icon: React.ReactNode;
}

const modeOptions: ModeOption[] = [
  {
    value: "email",
    label: "Email Address",
    description: "Login using your registered email",
    icon: <Mail className="w-5 h-5" />,
  },
  {
    value: "kanisa",
    label: "Account ID",
    description: "Login using your account number",
    icon: <User className="w-5 h-5" />,
  },
  {
    value: "customer",
    label: "Customer Account",
    description: "Login using your phone number & OTP",
    icon: <Smartphone className="w-5 h-5" />,
  },
];

const Login = () => {
  const { login } = useAuth();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();

  const [mode, setMode] = useState<LoginMode>("email");
  const [showModeSelector, setShowModeSelector] = useState(false);
  const [customerChoice, setCustomerChoice] = useState<"otp" | "google" | null>(null);
  const [identifier, setIdentifier] = useState("");
  const [password, setPassword] = useState("");
  const [otp, setOtp] = useState("");
  const [isOtpSent, setIsOtpSent] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [, setError] = useState<string | null>(null);

  const errorShownRef = React.useRef(false);

  useEffect(() => {
    const token = searchParams.get("token");
    const userData = searchParams.get("user");
    const errorParam = searchParams.get("error");

    if (errorParam && !errorShownRef.current) {
      errorShownRef.current = true;
      Swal.fire({
        icon: "error",
        title: "Login Failed",
        text: decodeURIComponent(errorParam),
        toast: true,
        position: "top-end",
        showConfirmButton: false,
        timer: 4000,
      });
      // Remove query parameters to clean up URL
      window.history.replaceState({}, document.title, window.location.pathname);
    } else if (token && userData) {
      try {
        const user = JSON.parse(decodeURIComponent(userData));
        login(user, token);
        Swal.fire({
          icon: "success",
          title: "Login Successful",
          text: `Welcome back, ${user.name}!`,
          toast: true,
          position: "top-end",
          showConfirmButton: false,
          timer: 3000,
        });
        navigate("/dashboard/customer");
      } catch (e) {
        console.error("Failed to parse user data from URL", e);
      }
    }
  }, [searchParams, login, navigate]);

  const handleModeSelect = useCallback((selectedMode: LoginMode) => {
    setMode(selectedMode);
    setCustomerChoice(null);
    setIdentifier("");
    setPassword("");
    setOtp("");
    setIsOtpSent(false);
    setShowModeSelector(false);
  }, []);

  const handleGoogleLogin = () => {
    // Redirect to backend google auth route
    const apiUrl = import.meta.env.VITE_API_URL;
    window.location.href = `${apiUrl}/auth/google/redirect`;
  };

  const handleSendOtp = async () => {
    if (!identifier) {
      Swal.fire({
        icon: "error",
        title: "Error",
        text: "Please enter your phone number",
        toast: true,
        position: "top-end",
        showConfirmButton: false,
        timer: 3000,
      });
      return;
    }

    setIsLoading(true);
    try {
      const response = await api.post("/customer/send-otp", {
        phone: identifier,
      });

      if (response.status === 200) {
        setIsOtpSent(true);
        Swal.fire({
          icon: "success",
          title: "OTP Sent",
          text: "A 6-digit verification code has been sent to your phone.",
          timer: 3000,
          toast: true,
          position: "top-end",
          showConfirmButton: false,
        });
      }
    } catch (err: any) {
      Swal.fire({
        icon: "error",
        title: "Failed to send OTP",
        text: err.response?.data?.message || "An error occurred",
        toast: true,
        position: "top-end",
        showConfirmButton: false,
        timer: 4000,
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();

    if (mode === "customer") {
      if (!isOtpSent) {
        await handleSendOtp();
        return;
      }

      if (!otp || otp.length !== 6) {
        Swal.fire({
          icon: "error",
          title: "Error",
          text: "Please enter a valid 6-digit OTP",
          toast: true,
          position: "top-end",
          showConfirmButton: false,
          timer: 3000,
        });
        return;
      }

      setIsLoading(true);
      try {
        const response = await api.post("/customer/login-otp", {
          phone: identifier,
          otp: otp,
        });

        if (response.data.status === 200 && response.data.token) {
          Swal.fire({
            icon: "success",
            title: "Login successful!",
            timer: 1500,
            toast: true,
            position: "top-end",
            showConfirmButton: false,
          });

          login(response.data.user, response.data.token);
          navigate("/dashboard/customer");
        }
      } catch (err: any) {
        Swal.fire({
          icon: "error",
          title: "Verification Failed",
          text: err.response?.data?.message || "Invalid OTP",
          toast: true,
          position: "top-end",
          showConfirmButton: false,
          timer: 4000,
        });
      } finally {
        setIsLoading(false);
      }
      return;
    }

    if (!identifier || !password) {
      const msg = "Please enter both credentials";
      setError(msg);

      Swal.fire({
        icon: "error",
        title: "Error",
        text: msg,
        toast: true,
        position: "top-end",
        showConfirmButton: false,
        timer: 3000,
      });

      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      const response = await api.post("/admin/login", {
        identifier,
        password,
      });

      if (response.data.status === 200 && response.data.token) {
        Swal.fire({
          icon: "success",
          title: "Login successful!",
          timer: 1500,
          toast: true,
          position: "top-end",
          showConfirmButton: false,
        });

        login(response.data.user, response.data.token);

        if (response.data.user.role === "vendor") {
          if (response.data.user.vendor_type === "Company") {
            navigate("/dashboard/company");
          } else if (response.data.user.vendor_type === "Individual") {
            navigate("/dashboard/individual");
          } else {
            navigate("/dashboard");
          }
        } else if (response.data.user.role === "customer") {
            navigate("/dashboard/customer");
        } else {
          navigate("/dashboard");
        }
      } else {
        const msg = response.data.message || "Authentication failed";
        setError(msg);

        Swal.fire({
          icon: "error",
          title: "Authentication Failed",
          text: msg,
          toast: true,
          position: "top-end",
          showConfirmButton: false,
          timer: 4000,
        });
      }
    } catch (err: any) {
      const msg =
        err.response?.data?.message ||
        err.message ||
        "An error occurred during login";

      setError(msg);

      Swal.fire({
        icon: "error",
        title: "Error",
        text: msg,
        toast: true,
        position: "top-end",
        showConfirmButton: false,
        timer: 4000,
      });
    } finally {
      setIsLoading(false);
    }
  };

  const currentMode =
    modeOptions.find((m) => m.value === mode) || modeOptions[0];

  return (
    <div className="min-h-screen bg-[#E8F4FD] dark:bg-slate-950 flex items-center justify-center p-4 relative overflow-hidden">

      {/* Background glow */}
      <div className="absolute -top-20 -left-20 w-96 h-96 bg-blue-400/20 blur-[120px] rounded-full" />
      <div className="absolute -bottom-20 -right-20 w-96 h-96 bg-indigo-400/20 blur-[120px] rounded-full" />

      {/* Main container */}
      <div className="w-full max-w-[380px] relative">

        {/* Login Card */}
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-xl p-6 sm:p-7 border border-slate-100 dark:border-slate-800">

          {/* Logo */}
          <motion.div
             initial={{ scale: 0.9, opacity: 0 }}
             animate={{ scale: 1, opacity: 1 }}
             className="flex flex-col items-center mb-5"
           >
             <div className="w-16 h-16 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center shadow-inner mb-3">
  <img src={Logo} alt="Token Utility System" className="w-12 h-12 object-contain" />
</div>

             <h2 className="text-lg font-bold text-slate-800 dark:text-white text-center">
               Token Utility System
             </h2>

             <p className="text-[11px] text-slate-400 mt-1 text-center">
               Powering secure token distribution and seamless utility management
             </p>
           </motion.div>

          <form onSubmit={handleLogin} className="space-y-3.5">

            {/* Login method selector */}
            <div>
              <label className="text-[11px] font-semibold text-slate-500 ml-1">
                Login method
              </label>

              <button
                type="button"
                onClick={() => setShowModeSelector(true)}
                className="w-full mt-1"
              >
                <div className="flex items-center justify-between px-3.5 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 hover:shadow-md transition">

                  <div className="flex items-center gap-3">
                    <motion.div
                      key={mode}
                      initial={{ scale: 0.8, opacity: 0 }}
                      animate={{ scale: 1, opacity: 1 }}
                      className="w-8 h-8 flex items-center justify-center rounded-lg bg-blue-50 dark:bg-blue-900/30 text-blue-600"
                    >
                      {currentMode.icon}
                    </motion.div>

                    <div className="text-left">
                      <p className="text-[13px] font-semibold text-slate-800 dark:text-white leading-tight">
                        {currentMode.label}
                      </p>

                      <p className="text-[10px] text-slate-400 leading-tight mt-0.5">
                        {currentMode.description}
                      </p>
                    </div>
                  </div>

                  <ChevronDown className="w-4 h-4 text-slate-400" />
                </div>
              </button>
            </div>

            {mode === "customer" && !customerChoice ? (
              <div className="grid grid-cols-2 gap-3 pt-2">
                <motion.button
                  whileHover={{ scale: 1.02 }}
                  whileTap={{ scale: 0.98 }}
                  type="button"
                  onClick={() => setCustomerChoice("otp")}
                  className="flex flex-col items-center justify-center p-4 rounded-2xl border border-slate-200 dark:border-slate-700 hover:border-blue-500 bg-white dark:bg-slate-800 transition shadow-sm group"
                >
                  <div className="w-12 h-12 rounded-xl bg-[#0A1F44] dark:bg-[#0A1F44] flex items-center justify-center text-blue-600 mb-2 group-hover:bg-blue-600 group-hover:text-white transition-colors">
                    <img
                      src="https://www.svgrepo.com/show/210458/mobile-phone-smartphone.svg"
                      alt="phone"
                      draggable={false}
                      className="w-5 h-5"
                    />
                  </div>

                  <span className="text-[11px] font-bold text-slate-700 dark:text-slate-200">
                    SMS OTP
                  </span>
                </motion.button>

                <motion.button
                  whileHover={{ scale: 1.02 }}
                  whileTap={{ scale: 0.98 }}
                  type="button"
                  onClick={() => setCustomerChoice("google")}
                  className="flex flex-col items-center justify-center p-4 rounded-2xl border border-slate-200 dark:border-slate-700 hover:border-blue-500 bg-white dark:bg-slate-800 transition shadow-sm group"
                >
                  <div className="w-12 h-12 rounded-xl bg-[#0A1F44] dark:bg-[#0A1F44] flex items-center justify-center text-blue-600 mb-2 group-hover:bg-blue-600 group-hover:text-white transition-colors">
                    <img
                      src="https://www.svgrepo.com/show/475656/google-color.svg"
                      alt="Google"
                      draggable={false}
                      className="w-5 h-5"
                    />
                  </div>
                  <span className="text-[11px] font-bold text-slate-700 dark:text-slate-200">Google</span>
                </motion.button>
              </div>
            ) : (
              <>
                {/* Identifier (Email, Account ID, or Phone) */}
                {(mode !== "customer" || customerChoice === "otp") && (
                  <div className="relative">
                    <div className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">
                      {mode === "email" ? <Mail size={15} /> : mode === "customer" ? <Phone size={15} /> : <User size={15} />}
                    </div>

                    <input
                      type={mode === "email" ? "email" : "text"}
                      placeholder={
                        mode === "email"
                          ? "Enter your email"
                          : mode === "customer"
                          ? "Enter your phone number"
                          : "Enter your account ID"
                      }
                      value={identifier}
                      disabled={mode === "customer" && isOtpSent && isLoading}
                      onChange={(e) => setIdentifier(e.target.value)}
                      className="w-full pl-9 pr-4 py-2.5 rounded-xl bg-slate-100 dark:bg-slate-800/80 border border-transparent focus:border-blue-500 focus:bg-white dark:focus:bg-slate-800 transition text-[13px] placeholder:text-slate-400"
                    />
                  </div>
                )}

                {/* Password or OTP */}
                {mode !== "customer" ? (
                  <div className="relative">
                    <Lock
                      size={15}
                      className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"
                    />

                    <input
                      type={showPassword ? "text" : "password"}
                      placeholder="Enter your password"
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      className="w-full pl-9 pr-9 py-2.5 rounded-xl bg-slate-100 dark:bg-slate-800/80 border border-transparent focus:border-blue-500 focus:bg-white dark:focus:bg-slate-800 transition text-[13px] placeholder:text-slate-400"
                    />

                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 transition-colors"
                    >
                      {showPassword ? <EyeOff size={15} /> : <Eye size={15} />}
                    </button>
                  </div>
                ) : customerChoice === "otp" && isOtpSent ? (
                  <motion.div
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="relative"
                  >
                    <Lock
                      size={15}
                      className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"
                    />
                    <input
                      type="text"
                      maxLength={6}
                      placeholder="Enter 6-digit OTP"
                      value={otp}
                      onChange={(e) => setOtp(e.target.value.replace(/\D/g, ""))}
                      className="w-full pl-9 pr-4 py-2.5 rounded-xl bg-slate-100 dark:bg-slate-800/80 border border-transparent focus:border-blue-500 focus:bg-white dark:focus:bg-slate-800 transition text-[13px] placeholder:text-slate-400 tracking-[0.5em] font-bold text-center"
                    />
                  </motion.div>
                ) : customerChoice === "google" ? (
                  <div className="text-center py-4">
                    <motion.button
                      whileHover={{ scale: 1.02 }}
                      whileTap={{ scale: 0.98 }}
                      type="button"
                      onClick={handleGoogleLogin}
                      className="w-full flex items-center justify-center gap-3 py-3 px-4 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 transition font-bold text-slate-700 dark:text-slate-200 shadow-sm"
                    >
                      <img
                        src="https://www.svgrepo.com/show/475656/google-color.svg"
                        alt="Google"
                        className="w-5 h-5"
                      />
                      Sign in with Google
                    </motion.button>
                  </div>
                ) : null}

                {/* Login/OTP button */}
                <AnimatePresence mode="wait">
                  {!isLoading && customerChoice !== "google" ? (
                    <motion.button
                      key={mode === "customer" && !isOtpSent ? "send-otp" : "login"}
                      type="submit"
                      whileHover={{ scale: 1.02 }}
                      whileTap={{ scale: 0.97 }}
                      className="w-full py-2.5 rounded-xl text-white text-[13px] font-bold bg-[#0A1F44] hover:bg-blue-700 shadow-lg shadow-blue-500/20"
                    >
                      {mode === "customer"
                        ? isOtpSent
                          ? "Verify & Login"
                          : "Send OTP"
                        : "Login to dashboard"}
                    </motion.button>
                  ) : isLoading ? (
                    <div className="flex justify-center py-2.5">
                      <div className="flex items-center gap-2 text-slate-500">
                        <div className="w-3.5 h-3.5 border-2 border-slate-300 border-t-blue-600 rounded-full animate-spin" />
                        <span className="text-[13px] font-medium">
                          {mode === "customer" && !isOtpSent ? "Sending OTP..." : "Logging in..."}
                        </span>
                      </div>
                    </div>
                  ) : null}
                </AnimatePresence>

                {mode === "customer" && (
                  <div className="flex items-center justify-center gap-4 mt-2">
                    {isOtpSent && !isLoading && (
                      <button
                        type="button"
                        onClick={handleSendOtp}
                        className="text-xs text-blue-600 hover:underline font-medium"
                      >
                        Resend OTP
                      </button>
                    )}

                    {!isLoading && (
                      <button
                        type="button"
                        onClick={() => {
                          setCustomerChoice(null);
                          setIsOtpSent(false);
                          setOtp("");
                        }}
                        className="text-xs text-slate-500 hover:text-slate-800 font-medium"
                      >
                        Change method
                      </button>
                    )}
                  </div>
                )}
              </>
            )}

            {mode !== "customer" && (
              <div className="text-center pt-1">
                <a
                  href="/forgot-password"
                  className="text-xs text-slate-500 hover:text-blue-600"
                >
                  Forgot password?
                </a>
              </div>
            )}
          </form>

          <div className="mt-6 pt-4 border-t border-slate-100 dark:border-slate-800 text-center text-xs text-slate-400">
            © {new Date().getFullYear()} TokenPap Utility Sytem . All rights reserved.
          </div>
        </div>

        {/* Login Method Selector */}
        <AnimatePresence>
          {showModeSelector && (
            <>
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                onClick={() => setShowModeSelector(false)}
                className="fixed inset-0 bg-black/40 backdrop-blur-sm z-20"
              />

              <div className="absolute bottom-0 left-0 right-0 z-30 pointer-events-none">
                <motion.div
                  initial={{ y: "100%" }}
                  animate={{ y: 0 }}
                  exit={{ y: "100%" }}
                  transition={{ type: "spring", damping: 25, stiffness: 200 }}
                  className="bg-white dark:bg-slate-900 rounded-t-[2rem] shadow-2xl border-t border-slate-100 dark:border-slate-800 pointer-events-auto"
                >
                  <div className="p-5">

                    <div className="w-10 h-1 bg-slate-200 dark:bg-slate-700 rounded-full mx-auto mb-3" />

                    <h3 className="text-sm font-bold text-center dark:text-white">
                      Login using
                    </h3>

                    <p className="text-center text-[11px] text-slate-400 mb-5">
                      Choose your preferred login method
                    </p>

                    <div className="space-y-2.5">
                      {modeOptions.map((option) => {
                        const isSelected = option.value === mode;

                        return (
                          <button
                            key={option.value}
                            onClick={() => handleModeSelect(option.value)}
                            className={`w-full flex items-center gap-3.5 p-3 rounded-xl border transition
                            ${
                              isSelected
                                ? "border-blue-500 bg-blue-50 dark:bg-blue-900/20 shadow-sm"
                                : "border-slate-200 dark:border-slate-700/60 hover:bg-slate-50 dark:hover:bg-slate-800"
                            }`}
                          >
                            <div
                              className={`w-9 h-9 flex items-center justify-center rounded-lg
                              ${
                                isSelected
                                  ? "bg-blue-600 text-white shadow-md shadow-blue-500/20"
                                  : "bg-slate-100 dark:bg-slate-800 text-slate-500"
                              }`}
                            >
                              {option.icon}
                            </div>

                            <div className="flex-1 text-left">
                              <p className="text-[13px] font-bold text-slate-800 dark:text-white leading-tight">
                                {option.label}
                              </p>

                              <p className="text-[10px] text-slate-400 leading-tight mt-0.5">
                                {option.description}
                              </p>
                            </div>

                            {isSelected && (
                              <CheckCircle2 className="text-blue-500 w-5 h-5" />
                            )}
                          </button>
                        );
                      })}
                    </div>

                    <button
                      onClick={() => setShowModeSelector(false)}
                      className="w-full mt-3 py-2 text-[13px] font-medium text-slate-500 hover:text-slate-800 dark:hover:text-slate-300 transition-colors"
                    >
                      Cancel
                    </button>

                  </div>
                </motion.div>
              </div>
            </>
          )}
        </AnimatePresence>

      </div>
    </div>
  );
};

export default Login;

import { useEffect, useState, useMemo } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import "sweetalert2/dist/sweetalert2.min.css";
import {
  Shield,
  Search,
  Plus,
  Edit2,
  Trash2,
  Lock,
  ChevronLeft,
  ChevronRight,
  X,
  Loader2,
  LayoutGrid,
  Users,
  DollarSign,
  Settings,
  Bell,
  FileText,
  ChevronDown,
  ChevronUp,
  ShieldCheck
} from "lucide-react";
import DashboardLoader from "@/lib/loader";

interface Permission {
  id: number;
  name: string;
  slug: string;
  description?: string;
}

interface Role {
  id: number;
  name: string;
  slug: string;
  description?: string;
  is_system_role: boolean;
  hierarchy_level: number;
  permissions?: Permission[];
}

interface PaginatedResponse<T> {
  roles: {
    data: T[];
    current_page: number;
    last_page: number;
    per_page: number;
    total: number;
  };
}

const CATEGORIES = [
  { id: 'members', name: 'Members', icon: Users, pattern: /member/ },
  { id: 'contributions', name: 'Contributions', icon: DollarSign, pattern: /contribution/ },
  { id: 'financial', name: 'Financial', icon: FileText, pattern: /financial/ },
  { id: 'system', name: 'System', icon: Settings, pattern: /(role|permission|system|user|congregation|audit)/ },
  { id: 'communication', name: 'Communication', icon: Bell, pattern: /(notification|communication|message)/ },
];

const RolesManagement = () => {
  const API_URL = import.meta.env.VITE_API_URL;
  const [roles, setRoles] = useState<Role[]>([]);
  const [allPermissions, setAllPermissions] = useState<Permission[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [query, setQuery] = useState("");
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingRole, setEditingRole] = useState<Role | null>(null);
  const [expandedCategories, setExpandedCategories] = useState<string[]>(['members']);

  // Form State
  const [formData, setFormData] = useState({
    name: "",
    slug: "",
    description: "",
    hierarchy_level: 0,
    permissions: [] as string[]
  });

  const token = useMemo(() => localStorage.getItem("token"), []);
  const headers = useMemo(() => ({ Authorization: `Bearer ${token}` }), [token]);

  const fetchRoles = async () => {
    setLoading(true);
    try {
      const res = await axios.get<PaginatedResponse<Role>>(
        `${API_URL}/admin/roles?search=${encodeURIComponent(query)}&page=${page}`,
        { headers }
      );
      setRoles(res.data.roles.data);
      setTotal(res.data.roles.total);
    } catch (error) {
      console.error("Error fetching roles:", error);
      Swal.fire("Error", "Failed to load roles", "error");
    } finally {
      setLoading(false);
    }
  };

  const fetchPermissions = async () => {
    try {
      const res = await axios.get<{ permissions: any }>(
        `${API_URL}/admin/permissions?per_page=100`,
        { headers }
      );
      const permissionsData = res.data.permissions.data || res.data.permissions;
      setAllPermissions(Array.isArray(permissionsData) ? permissionsData : []);
    } catch (error) {
      console.error("Error fetching permissions:", error);
    }
  };

  useEffect(() => {
    fetchPermissions();
  }, []);

  useEffect(() => {
    const handler = setTimeout(() => fetchRoles(), 300);
    return () => clearTimeout(handler);
  }, [query, page]);

  // Categorization Logic
  const categorizedPermissions = useMemo(() => {
    const groups: Record<string, Permission[]> = { others: [] };
    CATEGORIES.forEach(cat => groups[cat.id] = []);

    allPermissions.forEach(p => {
      let matched = false;
      for (const cat of CATEGORIES) {
        if (cat.pattern.test(p.slug)) {
          groups[cat.id].push(p);
          matched = true;
          break;
        }
      }
      if (!matched) groups.others.push(p);
    });

    return groups;
  }, [allPermissions]);

  const handleOpenModal = (role: Role | null = null) => {
    if (role) {
      setEditingRole(role);
      setFormData({
        name: role.name,
        slug: role.slug,
        description: role.description || "",
        hierarchy_level: role.hierarchy_level,
        permissions: role.permissions?.map(p => p.slug) || []
      });
    } else {
      setEditingRole(null);
      setFormData({
        name: "",
        slug: "",
        description: "",
        hierarchy_level: 0,
        permissions: []
      });
    }
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      if (editingRole) {
        await axios.put(`${API_URL}/admin/roles/${editingRole.slug}`, formData, { headers });
        Swal.fire({ icon: "success", title: "Role Updated", toast: true, position: "top-end", timer: 3000, showConfirmButton: false });
      } else {
        await axios.post(`${API_URL}/admin/roles`, formData, { headers });
        Swal.fire({ icon: "success", title: "Role Created", toast: true, position: "top-end", timer: 3000, showConfirmButton: false });
      }
      setIsModalOpen(false);
      fetchRoles();
    } catch (error: any) {
      Swal.fire("Error", error.response?.data?.message || "Operation failed", "error");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async (role: Role) => {
    if (role.is_system_role) {
      Swal.fire("Protected", "System roles cannot be deleted", "warning");
      return;
    }

    const result = await Swal.fire({
      title: "Delete Role?",
      text: `This will permanently delete "${role.name}". Users with this role will lose these permissions.`,
      icon: "warning",
      showCancelButton: true,
      confirmButtonColor: "#dc2626",
      cancelButtonColor: "#6b7280",
      confirmButtonText: "Delete",
      cancelButtonText: "Cancel",
      reverseButtons: true
    });

    if (result.isConfirmed) {
      try {
        await axios.delete(`${API_URL}/admin/roles/${role.slug}`, { headers });
        Swal.fire("Deleted", "Role has been deleted", "success");
        fetchRoles();
      } catch (error: any) {
        Swal.fire("Error", error.response?.data?.message || "Failed to delete role", "error");
      }
    }
  };

  const togglePermission = (slug: string) => {
    setFormData(prev => ({
      ...prev,
      permissions: prev.permissions.includes(slug)
        ? prev.permissions.filter(p => p !== slug)
        : [...prev.permissions, slug]
    }));
  };

  const toggleCategory = (categoryId: string) => {
    const categoryPermissions = categorizedPermissions[categoryId].map(p => p.slug);
    const allSelected = categoryPermissions.every(slug => formData.permissions.includes(slug));

    if (allSelected) {
      setFormData(prev => ({
        ...prev,
        permissions: prev.permissions.filter(slug => !categoryPermissions.includes(slug))
      }));
    } else {
      setFormData(prev => ({
        ...prev,
        permissions: Array.from(new Set([...prev.permissions, ...categoryPermissions]))
      }));
    }
  };

  const toggleCategoryExpand = (categoryId: string) => {
    setExpandedCategories(prev =>
      prev.includes(categoryId)
        ? prev.filter(id => id !== categoryId)
        : [...prev, categoryId]
    );
  };

  const getCategoryStatus = (categoryId: string) => {
    const items = categorizedPermissions[categoryId] || [];
    if (items.length === 0) return 'empty';
    const selectedCount = items.filter(p => formData.permissions.includes(p.slug)).length;
    if (selectedCount === 0) return 'none';
    if (selectedCount === items.length) return 'all';
    return 'partial';
  };

  return (
    <div className="min-h-screen bg-gray-50/50 p-6 md:p-8">
      {/* Header */}
      <div className="max-w-7xl mx-auto mb-8">
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
          <div>
            <h1 className="text-2xl font-semibold text-gray-900">Role Management</h1>
            <p className="text-sm text-gray-500 mt-1">Manage access roles and permission assignments</p>
          </div>
          <button
            onClick={() => handleOpenModal()}
            className="inline-flex items-center justify-center gap-2 px-4 py-2 bg-blue-600 text-white text-sm font-medium rounded-lg hover:bg-blue-700 transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2"
          >
            <Plus className="w-4 h-4" />
            New Role
          </button>
        </div>
      </div>

      {/* Search and Filters */}
      <div className="max-w-7xl mx-auto mb-6">
        <div className="relative max-w-md">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-4 h-4" />
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Search roles..."
            className="w-full pl-10 pr-4 py-2 bg-white border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
        </div>
      </div>

      {/* Content */}
      <div className="max-w-7xl mx-auto">
        {loading ? (
          <div className="h-96 flex items-center justify-center bg-white rounded-lg border border-gray-200">
            <DashboardLoader title="Loading roles..." />
          </div>
        ) : roles.length === 0 ? (
          <div className="text-center py-16 bg-white rounded-lg border border-gray-200 border-dashed">
            <Shield className="w-12 h-12 text-gray-300 mx-auto mb-4" />
            <h3 className="text-lg font-medium text-gray-900 mb-1">No roles found</h3>
            <p className="text-sm text-gray-500">Create your first role to get started</p>
          </div>
        ) : (
          <div className="bg-white border border-gray-200 rounded-lg overflow-hidden">
            <table className="w-full text-left text-sm">
              <thead className="bg-gray-50 border-b border-gray-200">
                <tr>
                  <th className="px-6 py-4 font-medium text-gray-700">Role</th>
                  <th className="px-6 py-4 font-medium text-gray-700">Level</th>
                  <th className="px-6 py-4 font-medium text-gray-700">Permissions</th>
                  <th className="px-6 py-4 font-medium text-gray-700">Type</th>
                  <th className="px-6 py-4 font-medium text-gray-700 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {roles.map((role) => (
                  <tr key={role.id} className="hover:bg-gray-50/50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className={`p-2 rounded-lg ${role.is_system_role ? 'bg-amber-50 text-amber-600' : 'bg-blue-50 text-blue-600'}`}>
                          {role.is_system_role ? <Lock className="w-4 h-4" /> : <ShieldCheck className="w-4 h-4" />}
                        </div>
                        <div>
                          <div className="font-medium text-gray-900 capitalize">{role.name}</div>
                          <div className="text-xs text-gray-500 font-mono mt-0.5">{role.slug}</div>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-gray-100 text-gray-800">
                        Level {role.hierarchy_level}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <span className="text-sm text-gray-600">
                          {role.permissions?.length || 0} permissions
                        </span>
                        {role.permissions && role.permissions.length > 0 && (
                          <div className="flex -space-x-1">
                            {role.permissions.slice(0, 3).map((p) => (
                              <div key={p.id} className="w-5 h-5 rounded-full bg-blue-100 border-2 border-white flex items-center justify-center" title={p.name}>
                                <span className="text-[8px] font-bold text-blue-600">{p.name.charAt(0).toUpperCase()}</span>
                              </div>
                            ))}
                            {role.permissions.length > 3 && (
                              <div className="w-5 h-5 rounded-full bg-gray-100 border-2 border-white flex items-center justify-center">
                                <span className="text-[8px] font-medium text-gray-600">+{role.permissions.length - 3}</span>
                              </div>
                            )}
                          </div>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      {role.is_system_role ? (
                        <span className="inline-flex items-center gap-1.5 text-xs text-amber-600 font-medium">
                          <Lock className="w-3 h-3" />
                          System
                        </span>
                      ) : (
                        <span className="inline-flex items-center gap-1.5 text-xs text-gray-500">
                          <ShieldCheck className="w-3 h-3" />
                          Custom
                        </span>
                      )}
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex items-center justify-end gap-2">
                        <button
                          onClick={() => handleOpenModal(role)}
                          className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                          title="Edit role"
                        >
                          <Edit2 className="w-4 h-4" />
                        </button>
                        {!role.is_system_role && (
                          <button
                            onClick={() => handleDelete(role)}
                            className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                            title="Delete role"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>

            {/* Pagination */}
            {total > 0 && (
              <div className="px-6 py-4 border-t border-gray-200 bg-gray-50 flex items-center justify-between">
                <div className="text-sm text-gray-500">
                  Showing <span className="font-medium text-gray-900">{roles.length}</span> of <span className="font-medium text-gray-900">{total}</span> roles
                </div>
                <div className="flex items-center gap-2">
                  <button
                    onClick={() => setPage(p => Math.max(1, p - 1))}
                    disabled={page === 1}
                    className="p-2 border border-gray-200 rounded-lg bg-white text-gray-600 hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
                  >
                    <ChevronLeft className="w-4 h-4" />
                  </button>
                  <span className="text-sm font-medium text-gray-900 min-w-[3rem] text-center">
                    {page}
                  </span>
                  <button
                    onClick={() => setPage(p => p + 1)}
                    disabled={roles.length < 20}
                    className="p-2 border border-gray-200 rounded-lg bg-white text-gray-600 hover:bg-gray-50 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
                  >
                    <ChevronRight className="w-4 h-4" />
                  </button>
                </div>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 overflow-y-auto">
          <div className="flex min-h-screen items-center justify-center p-4 text-center sm:p-0">
            <div
              className="fixed inset-0 bg-gray-500 bg-opacity-75 transition-opacity"
              onClick={() => setIsModalOpen(false)}
            />

            <div className="relative transform overflow-hidden rounded-xl bg-white text-left shadow-2xl transition-all sm:my-8 sm:w-full sm:max-w-3xl max-h-[90vh] flex flex-col">
              {/* Modal Header */}
              <div className="bg-white border-b border-gray-100 px-5 py-3 flex items-center justify-between shrink-0">
                <div className="flex items-center gap-2">
                  <div className="p-1.5 bg-blue-50 rounded-md">
                    <ShieldCheck className="w-4 h-4 text-blue-600" />
                  </div>
                  <div>
                    <h3 className="text-base font-bold text-gray-900 leading-none">
                      {editingRole ? "Edit Role" : "Create New Role"}
                    </h3>
                    <p className="text-[11px] text-gray-500 mt-0.5">
                      {editingRole ? "Configure hierarchy & permissions" : "Register a new access entity"}
                    </p>
                  </div>
                </div>
                <button
                  onClick={() => setIsModalOpen(false)}
                  className="text-gray-400 hover:text-gray-600 p-1.5 hover:bg-gray-100 rounded-lg transition-colors"
                >
                  <X className="w-4 h-4" />
                </button>
              </div>

              {/* Modal Body */}
              <div className="flex-1 overflow-y-auto p-5">
                <form id="roleForm" onSubmit={handleSubmit} className="space-y-5">
                  <div className="grid grid-cols-1 lg:grid-cols-12 gap-5">
                    {/* Left Column - Basic Info */}
                    <div className="lg:col-span-12 grid grid-cols-1 sm:grid-cols-2 gap-4">
                      <div className="space-y-3">
                        <div>
                          <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1">
                            Role Name
                          </label>
                          <input
                            type="text"
                            required
                            value={formData.name}
                            onChange={e => setFormData({ ...formData, name: e.target.value })}
                            placeholder="e.g. Finance Officer"
                            disabled={editingRole?.is_system_role}
                            className="w-full px-3 py-1.5 border border-gray-300 rounded-lg focus:ring-1 focus:ring-blue-500 focus:border-blue-500 text-sm disabled:bg-gray-50 disabled:text-gray-500 font-medium"
                          />
                        </div>

                        <div>
                          <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1">
                            Slug
                          </label>
                          <input
                            type="text"
                            required
                            value={formData.slug}
                            onChange={e => setFormData({ ...formData, slug: e.target.value.toLowerCase().replace(/\s+/g, '_') })}
                            placeholder="finance_officer"
                            disabled={editingRole !== null}
                            className="w-full px-3 py-1.5 border border-gray-300 rounded-lg focus:ring-1 focus:ring-blue-500 focus:border-blue-500 text-sm font-mono disabled:bg-gray-50 disabled:text-gray-500"
                          />
                        </div>
                      </div>

                      <div className="space-y-3">
                        <div>
                          <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1">
                            Description
                          </label>
                          <textarea
                            value={formData.description}
                            onChange={e => setFormData({ ...formData, description: e.target.value })}
                            placeholder="Briefly state responsibilities..."
                            rows={3}
                            className="w-full px-3 py-1.5 border border-gray-300 rounded-lg focus:ring-1 focus:ring-blue-500 focus:border-blue-500 text-sm resize-none"
                          />
                        </div>
                      </div>
                    </div>

                    <div className="lg:col-span-12">
                      <div className="flex items-center gap-4 bg-gray-50 p-3 rounded-lg border border-gray-100">
                        <div className="flex-1">
                          <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-1">
                            Authority Level: <span className="text-blue-600">{formData.hierarchy_level}</span>
                          </label>
                          <input
                            type="range"
                            min="0"
                            max="100"
                            value={formData.hierarchy_level}
                            onChange={e => setFormData({ ...formData, hierarchy_level: parseInt(e.target.value) })}
                            className="w-full h-1.5 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
                          />
                        </div>
                        {editingRole?.is_system_role && (
                          <div className="flex items-center gap-2 text-[10px] text-amber-700 font-bold bg-amber-100/50 px-2 py-1 rounded">
                            <Lock className="w-3 h-3" /> System Role (Metadata Locked)
                          </div>
                        )}
                      </div>
                    </div>

                    {/* Matrix Section */}
                    <div className="lg:col-span-12 mt-2">
                      <div className="flex items-center justify-between mb-3 px-1">
                        <h4 className="text-sm font-black text-gray-900 uppercase tracking-tighter">Permission Matrix</h4>
                        <span className="text-[10px] font-bold text-blue-600 bg-blue-50 px-2 py-0.5 rounded-full border border-blue-100">
                          {formData.permissions.length} Activated
                        </span>
                      </div>

                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {CATEGORIES.map(category => {
                          const items = categorizedPermissions[category.id] || [];
                          const status = getCategoryStatus(category.id);
                          const isExpanded = expandedCategories.includes(category.id);

                          if (items.length === 0) return null;

                          return (
                            <div key={category.id} className="border border-gray-100 rounded-xl overflow-hidden shadow-sm">
                              <div className="flex items-center justify-between p-3 bg-gray-50 border-b border-gray-100">
                                <div
                                  className="flex items-center gap-2 cursor-pointer select-none"
                                  onClick={() => toggleCategoryExpand(category.id)}
                                >
                                  <category.icon className="w-3.5 h-3.5 text-gray-400" />
                                  <span className="font-bold text-xs text-gray-700">{category.name}</span>
                                  {isExpanded ? <ChevronUp className="w-3 h-3 text-gray-400" /> : <ChevronDown className="w-3 h-3 text-gray-400" />}
                                </div>
                                <button
                                  type="button"
                                  onClick={() => toggleCategory(category.id)}
                                  className={`text-[9px] font-black px-2 py-1 rounded transition-all ${status === 'all'
                                      ? 'bg-amber-100 text-amber-700'
                                      : 'bg-blue-100 text-blue-700 hover:bg-blue-200'
                                    }`}
                                >
                                  {status === 'all' ? 'DESELECT' : 'SELECT ALL'}
                                </button>
                              </div>

                              {isExpanded && (
                                <div className="p-2 bg-white grid grid-cols-1 gap-1">
                                  {items.map(permission => {
                                    const isSelected = formData.permissions.includes(permission.slug);
                                    return (
                                      <label
                                        key={permission.id}
                                        className={`flex items-center gap-3 p-2 rounded-lg cursor-pointer transition-colors border ${isSelected ? 'bg-blue-50/30 border-blue-100' : 'bg-transparent border-transparent hover:bg-gray-50'
                                          }`}
                                      >
                                        <input
                                          type="checkbox"
                                          checked={isSelected}
                                          onChange={() => togglePermission(permission.slug)}
                                          className="w-3.5 h-3.5 text-blue-600 border-gray-300 rounded focus:ring-0"
                                        />
                                        <div className="flex-1 min-w-0">
                                          <div className={`text-[12px] font-bold ${isSelected ? 'text-blue-700' : 'text-gray-700'}`}>
                                            {permission.name}
                                          </div>
                                          <p className="text-[9px] text-gray-400 font-mono truncate">{permission.slug}</p>
                                        </div>
                                      </label>
                                    );
                                  })}
                                </div>
                              )}
                            </div>
                          );
                        })}

                        {/* Uncategorized */}
                        {categorizedPermissions.others.length > 0 && (
                          <div className="border border-gray-100 rounded-xl overflow-hidden shadow-sm">
                            <div
                              className="w-full px-4 py-3 bg-gray-50 flex items-center justify-between hover:bg-gray-100 transition-colors cursor-pointer"
                              onClick={() => toggleCategoryExpand('others')}
                            >
                              <div className="flex items-center gap-3">
                                <LayoutGrid className="w-3.5 h-3.5 text-gray-400" />
                                <span className="font-bold text-xs text-gray-700">Others</span>
                              </div>
                              {expandedCategories.includes('others') ? <ChevronUp className="w-3 h-3 text-gray-400" /> : <ChevronDown className="w-3 h-3 text-gray-400" />}
                            </div>

                            {expandedCategories.includes('others') && (
                              <div className="p-2 bg-white space-y-1">
                                {categorizedPermissions.others.map(permission => {
                                  const isSelected = formData.permissions.includes(permission.slug);
                                  return (
                                    <label key={permission.id} className="flex items-center gap-3 p-2 rounded-lg hover:bg-gray-50 cursor-pointer border border-transparent">
                                      <input
                                        type="checkbox"
                                        checked={isSelected}
                                        onChange={() => togglePermission(permission.slug)}
                                        className="w-3.5 h-3.5 text-blue-600 border-gray-300 rounded focus:ring-0"
                                      />
                                      <div className="flex-1">
                                        <div className="text-[12px] font-bold text-gray-700">{permission.name}</div>
                                        <div className="text-[9px] text-gray-400 font-mono">{permission.slug}</div>
                                      </div>
                                    </label>
                                  );
                                })}
                              </div>
                            )}
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                </form>
              </div>

              {/* Modal Footer */}
              <div className="bg-gray-50 px-5 py-3 border-t border-gray-100 flex justify-end gap-2 shrink-0">
                <button
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="px-4 py-1.5 bg-white border border-gray-300 text-gray-700 text-[12px] font-bold rounded-lg hover:bg-gray-50 transition-colors"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  form="roleForm"
                  disabled={isSubmitting}
                  className="inline-flex items-center gap-2 px-6 py-1.5 bg-blue-600 text-white text-[12px] font-black rounded-lg hover:bg-blue-700 transition-colors shadow-lg shadow-blue-500/20 disabled:opacity-50"
                >
                  {isSubmitting && <Loader2 className="w-3 h-3 animate-spin" />}
                  {editingRole ? "SAVE CHANGES" : "CREATE ROLE"}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default RolesManagement;

import { useEffect, useState } from 'react';
import { useOutletContext } from 'react-router-dom';
import axios from 'axios';
import { Settings, Save, Eye, EyeOff, MessageSquare, RefreshCw, ChevronDown, Globe } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import Swal from 'sweetalert2';
import DashboardLoader from '@/lib/loader';

interface SystemConfig {
  id: number;
  key: string;
  value: string;
  type: string;
  category: string;
  description: string | null;
  is_encrypted: boolean;
  is_masked?: boolean;
  created_at: string;
  updated_at: string;
}

interface UserContext {
  user: {
    id: string;
    name: string;
    email: string;
    role: string;
  };
}

const SystemConfigPage = () => {
  const { user } = useOutletContext<UserContext>();
  const [configs, setConfigs] = useState<SystemConfig[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [visiblePasswords, setVisiblePasswords] = useState<Record<string, boolean>>({});
  const [editedConfigs, setEditedConfigs] = useState<Record<string, string>>({});
  const [activeTab, setActiveTab] = useState<'sms' | 'mpesa'>('sms');

  const [isVendor, setIsVendor] = useState(false);
  const [vendorEmail, setVendorEmail] = useState('');
  const [isTabLoading, setIsTabLoading] = useState(false);

  const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:8000/api';

  useEffect(() => {
    if (user) {
      console.log('User detected:', { email: user.email, role: user.role });
      const vendor = user.role === 'vendor';
      setIsVendor(vendor);
      setVendorEmail(user.email || '');
    } else {
      console.log('User is null or undefined');
      setIsVendor(false);
      setVendorEmail('');
    }
  }, [user?.email, user?.role]); // Use primitive strings, not the user object directly, to avoid infinite renders

  useEffect(() => {
    // Only load configs if user is available
    if (!user) {
      console.log('Waiting for user to load...');
      return;
    }

    const loadWithTransition = async () => {
      setIsTabLoading(true);
      await loadConfigs();
      // Small delay for smooth transition
      setTimeout(() => setIsTabLoading(false), 200);
    };
    loadWithTransition();
    // Use primitive dependencies to prevent infinite re-fetching
  }, [activeTab, user?.email, user?.role]);


  const loadConfigs = async () => {
    // Double-check user role from context
    const currentUser = user;

    // Don't load if user is not available yet
    if (!currentUser) {
      console.log('User not available yet, skipping config load');
      return;
    }

    const isVendorUser = currentUser.role === 'vendor';
    const currentVendorEmail = currentUser.email || '';

    try {
      if (!isTabLoading) {
        setLoading(true);
      }
      const token = localStorage.getItem('token');

      if (!token) {
        console.error('No token found');
        return;
      }

      console.log('Loading configs:', {
        isVendor,
        vendorEmail,
        isVendorUser,
        currentVendorEmail,
        userRole: currentUser?.role,
        userEmail: currentUser?.email,
      });

      let configsData: SystemConfig[] = [];

      if (isVendorUser && currentVendorEmail) {
        // Load vendor-specific config
        console.log('Loading vendor config for:', currentVendorEmail);
        try {
          const response = await axios.get(`${API_URL}/vendor/config`, {
            headers: {
              Authorization: `Bearer ${token}`,
            },
          });

          console.log('Vendor config response:', response.data);

          if (response.data.status === 200) {
            const vendorConfig = activeTab === 'sms' ? response.data.sms_config : response.data.mpesa_config;

            // Transform vendor config object to SystemConfig[] format
            if (activeTab === 'sms') {
              configsData = [
                {
                  id: 1,
                  key: 'sms_provider',
                  value: vendorConfig?.provider || '',
                  type: 'string',
                  category: 'sms',
                  description: 'SMS Provider name (advanta, fornax, twilio, etc.)',
                  is_encrypted: false,
                  is_masked: false,
                  created_at: '',
                  updated_at: '',
                },
                {
                  id: 2,
                  key: 'sms_api_url',
                  value: vendorConfig?.api_url || '',
                  type: 'string',
                  category: 'sms',
                  description: 'SMS API endpoint URL',
                  is_encrypted: false,
                  is_masked: false,
                  created_at: '',
                  updated_at: '',
                },
                {
                  id: 3,
                  key: 'sms_api_key',
                  value: vendorConfig?.api_key ? '***' : '',
                  type: 'string',
                  category: 'sms',
                  description: 'SMS API Key',
                  is_encrypted: true,
                  is_masked: !!vendorConfig?.api_key,
                  created_at: '',
                  updated_at: '',
                },
                {
                  id: 4,
                  key: 'sms_partner_id',
                  value: vendorConfig?.partner_id || '',
                  type: 'string',
                  category: 'sms',
                  description: 'SMS Partner ID',
                  is_encrypted: false,
                  is_masked: false,
                  created_at: '',
                  updated_at: '',
                },
                {
                  id: 5,
                  key: 'sms_shortcode',
                  value: vendorConfig?.shortcode || '',
                  type: 'string',
                  category: 'sms',
                  description: 'SMS Shortcode/Sender ID',
                  is_encrypted: false,
                  is_masked: false,
                  created_at: '',
                  updated_at: '',
                },
                {
                  id: 6,
                  key: 'sms_enabled',
                  value: vendorConfig?.enabled ? 'true' : 'false',
                  type: 'boolean',
                  category: 'sms',
                  description: 'Enable or disable SMS service',
                  is_encrypted: false,
                  is_masked: false,
                  created_at: '',
                  updated_at: '',
                },
              ];
            } else {
              // Mpesa config
              configsData = [
                {
                  id: 7,
                  key: 'mpesa_consumer_key',
                  value: vendorConfig?.consumer_key ? '***' : '',
                  type: 'string',
                  category: 'mpesa',
                  description: 'M-Pesa Consumer Key',
                  is_encrypted: true,
                  is_masked: !!vendorConfig?.consumer_key,
                  created_at: '',
                  updated_at: '',
                },
                {
                  id: 8,
                  key: 'mpesa_consumer_secret',
                  value: vendorConfig?.consumer_secret ? '***' : '',
                  type: 'string',
                  category: 'mpesa',
                  description: 'M-Pesa Consumer Secret',
                  is_encrypted: true,
                  is_masked: !!vendorConfig?.consumer_secret,
                  created_at: '',
                  updated_at: '',
                },
                {
                  id: 9,
                  key: 'mpesa_passkey',
                  value: vendorConfig?.passkey ? '***' : '',
                  type: 'string',
                  category: 'mpesa',
                  description: 'M-Pesa Passkey (for STK Push)',
                  is_encrypted: true,
                  is_masked: !!vendorConfig?.passkey,
                  created_at: '',
                  updated_at: '',
                },
                {
                  id: 10,
                  key: 'mpesa_shortcode',
                  value: vendorConfig?.shortcode || '',
                  type: 'string',
                  category: 'mpesa',
                  description: 'M-Pesa Business Shortcode (Paybill/Store)',
                  is_encrypted: false,
                  is_masked: false,
                  created_at: '',
                  updated_at: '',
                },
                {
                  id: 11,
                  key: 'mpesa_till_no',
                  value: vendorConfig?.till_no || '',
                  type: 'string',
                  category: 'mpesa',
                  description: 'M-Pesa Till Number (if applicable)',
                  is_encrypted: false,
                  is_masked: false,
                  created_at: '',
                  updated_at: '',
                },
                {
                  id: 12,
                  key: 'mpesa_env',
                  value: vendorConfig?.env || 'sandbox',
                  type: 'string',
                  category: 'mpesa',
                  description: 'M-Pesa Environment (sandbox or live)',
                  is_encrypted: false,
                  is_masked: false,
                  created_at: '',
                  updated_at: '',
                },
                {
                  id: 13,
                  key: 'mpesa_callback_url',
                  value: vendorConfig?.callback_url || '',
                  type: 'string',
                  category: 'mpesa',
                  description: 'M-Pesa Callback URL',
                  is_encrypted: false,
                  is_masked: false,
                  created_at: '',
                  updated_at: '',
                },
                {
                  id: 14,
                  key: 'mpesa_transaction_type',
                  value: vendorConfig?.transaction_type || 'CustomerBuyGoodsOnline',
                  type: 'string',
                  category: 'mpesa',
                  description: 'M-Pesa Transaction Type (CustomerPayBillOnline or CustomerBuyGoodsOnline)',
                  is_encrypted: false,
                  is_masked: false,
                  created_at: '',
                  updated_at: '',
                },
              ];
            }
          }
        } catch (vendorError: any) {
          console.error('Error loading vendor config:', vendorError);
          // If vendor config fails, fallback to global config
          if (vendorError.response?.status === 404) {
            console.log('Vendor not found, falling back to global config');
          } else {
            throw vendorError;
          }
        }
      }

      // Load global SystemConfig for admins or if vendor config failed
      if (!isVendorUser || configsData.length === 0) {
        console.log('Loading global SystemConfig for admin');
        const response = await axios.get(`${API_URL}/admin/system-config/category/${activeTab}`, {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        });

        if (response.data.status === 200) {
          configsData = response.data.configs;
        }
      }

      setConfigs(configsData);
      // Initialize edited configs with current values
      const initial: Record<string, string> = {};
      configsData.forEach((config: SystemConfig) => {
        if (!config.is_masked) {
          initial[config.key] = config.value;
        }
      });
      setEditedConfigs(initial);
      console.log('Configs loaded successfully:', configsData.length, 'items');
    } catch (error: any) {
      console.error('Error loading configs:', error);
      const errorMessage = error.response?.data?.message || error.message || 'Failed to load configuration';

      // If vendor config fails with 404, silently fallback to global config
      if (error.response?.status === 404 && isVendorUser) {
        console.log('Vendor config not found, loading global config as fallback');
        try {
          const response = await axios.get(`${API_URL}/admin/system-config/category/${activeTab}`, {
            headers: {
              Authorization: `Bearer ${localStorage.getItem('token')}`,
            },
          });
          if (response.data.status === 200) {
            const configsData = response.data.configs;
            setConfigs(configsData);
            const initial: Record<string, string> = {};
            configsData.forEach((config: SystemConfig) => {
              if (!config.is_masked) {
                initial[config.key] = config.value;
              }
            });
            setEditedConfigs(initial);
            return; // Successfully loaded global config
          }
        } catch (fallbackError) {
          console.error('Fallback to global config also failed:', fallbackError);
        }
      }

      Swal.fire({
        icon: 'error',
        title: 'Error',
        text: errorMessage,
        toast: true,
        position: 'top-end',
        showConfirmButton: false,
        timer: 3000
      });
    } finally {
      if (!isTabLoading) {
        setLoading(false);
      }
    }
  };

  const handleValueChange = (key: string, value: string) => {
    setEditedConfigs((prev) => ({
      ...prev,
      [key]: value,
    }));
  };

  const togglePasswordVisibility = (key: string) => {
    setVisiblePasswords((prev) => ({
      ...prev,
      [key]: !prev[key],
    }));
  };

  const handleSave = async () => {
    try {
      setSaving(true);
      const token = localStorage.getItem('token');

      if (isVendor) {
        // Save vendor-specific config
        const vendorConfig: any = {};

        Object.entries(editedConfigs).forEach(([key, value]) => {
          const originalConfig = configs.find(c => c.key === key);
          if (!originalConfig) return;

          // Skip if value hasn't changed (unless it's a masked/encrypted field)
          if (!originalConfig.is_masked && value === originalConfig.value) {
            return;
          }

          // Skip empty values for masked fields unless they're being updated
          if (originalConfig.is_masked && (!value || !value.trim())) {
            return;
          }

          // Map SystemConfig keys to vendor config structure
          if (activeTab === 'sms') {
            switch (key) {
              case 'sms_provider':
                vendorConfig.provider = value;
                break;
              case 'sms_api_url':
                vendorConfig.api_url = value;
                break;
              case 'sms_api_key':
                if (value.trim()) vendorConfig.api_key = value;
                break;
              case 'sms_partner_id':
                vendorConfig.partner_id = value;
                break;
              case 'sms_shortcode':
                vendorConfig.shortcode = value;
                break;
              case 'sms_enabled':
                vendorConfig.enabled = value === 'true';
                break;
            }
          } else {
            // Mpesa
            switch (key) {
              case 'mpesa_consumer_key':
                if (value.trim()) vendorConfig.consumer_key = value;
                break;
              case 'mpesa_consumer_secret':
                if (value.trim()) vendorConfig.consumer_secret = value;
                break;
              case 'mpesa_passkey':
                if (value.trim()) vendorConfig.passkey = value;
                break;
              case 'mpesa_shortcode':
                vendorConfig.shortcode = value;
                break;
              case 'mpesa_till_no':
                vendorConfig.till_no = value;
                break;
              case 'mpesa_env':
                vendorConfig.env = value;
                break;
              case 'mpesa_callback_url':
                vendorConfig.callback_url = value;
                break;
              case 'mpesa_transaction_type':
                vendorConfig.transaction_type = value;
                break;
            }
          }
        });

        const payload: any = {};
        if (activeTab === 'sms') {
          payload.sms_config = vendorConfig;
        } else {
          payload.mpesa_config = vendorConfig;
        }

        const response = await axios.put(
          `${API_URL}/vendor/config`,
          payload,
          {
            headers: {
              Authorization: `Bearer ${token}`,
            },
          }
        );

        if (response.data.status === 200) {
          Swal.fire({
            icon: 'success',
            title: 'Success',
            text: `Your ${activeTab.toUpperCase()} configuration updated successfully`,
            toast: true,
            position: 'top-end',
            showConfirmButton: false,
            timer: 3000
          });
          // Reload configs smoothly without full page reload
          setIsTabLoading(true);
          await loadConfigs();
          setTimeout(() => {
            setIsTabLoading(false);
            setVisiblePasswords({});
          }, 300);
        }
      } else {
        // Save global SystemConfig for admins
        const configsToUpdate = Object.entries(editedConfigs)
          .filter(([key, value]) => {
            const originalConfig = configs.find(c => c.key === key);
            if (!originalConfig) return false;
            // For encrypted/masked values, any non-empty value is considered a change
            if (originalConfig.is_masked) {
              return value && value.trim() !== '';
            }
            // For other values, check if it's different from original (treating null/undefined as empty string)
            const originalValue = originalConfig.value || '';
            const newValue = value || '';
            return newValue !== originalValue;
          })
          .map(([key, value]) => ({
            key,
            value,
          }));

        const response = await axios.post(
          `${API_URL}/admin/system-config/bulk-update`,
          { configs: configsToUpdate },
          {
            headers: {
              Authorization: `Bearer ${token}`,
            },
          }
        );

        if (response.data.status === 200) {
          Swal.fire({
            icon: 'success',
            title: 'Success',
            text: `${activeTab.toUpperCase()} configuration updated successfully`,
            toast: true,
            position: 'top-end',
            showConfirmButton: false,
            timer: 3000
          });
          // Reload configs smoothly without full page reload
          setIsTabLoading(true);
          await loadConfigs();
          setTimeout(() => {
            setIsTabLoading(false);
            setVisiblePasswords({});
          }, 300);
        }
      }
    } catch (error: any) {
      console.error('Error saving configs:', error);
      Swal.fire({
        icon: 'error',
        title: 'Error',
        text: error.response?.data?.message || 'Failed to save configuration',
        toast: true,
        position: 'top-end',
        showConfirmButton: false,
        timer: 3000
      });
    } finally {
      setSaving(false);
    }
  };



  const hasChanges = () => {
    return Object.keys(editedConfigs).length > 0;
  };

  // Show loader if user is not loaded yet or initial loading
  if (!user || loading) {
    return <DashboardLoader />;
  }

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 p-6">
      <div className="max-w-4xl mx-auto">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
